-- LINE OSS CRM D1 Schema
-- IDs are TEXT and generated by app code using crypto.randomUUID()

-- ============================================================
-- Friends
-- ============================================================
CREATE TABLE IF NOT EXISTS friends (
  id               TEXT PRIMARY KEY,
  line_user_id     TEXT UNIQUE NOT NULL,
  display_name     TEXT,
  picture_url      TEXT,
  status_message   TEXT,
  is_following     INTEGER NOT NULL DEFAULT 1,
  source           TEXT,
  user_id          TEXT,
  ig_igsid         TEXT,
  score            INTEGER NOT NULL DEFAULT 0,
  created_at       TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at       TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_friends_line_user_id ON friends (line_user_id);
CREATE INDEX IF NOT EXISTS idx_friends_user_id ON friends (user_id);
CREATE INDEX IF NOT EXISTS idx_friends_ig_igsid ON friends (ig_igsid);
CREATE INDEX IF NOT EXISTS idx_friends_source ON friends (source);

-- ============================================================
-- Tags
-- ============================================================
CREATE TABLE IF NOT EXISTS tags (
  id         TEXT PRIMARY KEY,
  name       TEXT UNIQUE NOT NULL,
  color      TEXT NOT NULL DEFAULT '#3B82F6',
  created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

-- ============================================================
-- Friend <-> Tag join
-- ============================================================
CREATE TABLE IF NOT EXISTS friend_tags (
  friend_id   TEXT NOT NULL REFERENCES friends (id) ON DELETE CASCADE,
  tag_id      TEXT NOT NULL REFERENCES tags (id) ON DELETE CASCADE,
  assigned_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  PRIMARY KEY (friend_id, tag_id)
);

CREATE INDEX IF NOT EXISTS idx_friend_tags_tag_id ON friend_tags (tag_id);

-- ============================================================
-- Scenarios
-- ============================================================
CREATE TABLE IF NOT EXISTS scenarios (
  id              TEXT PRIMARY KEY,
  name            TEXT NOT NULL,
  description     TEXT,
  trigger_type    TEXT NOT NULL CHECK (trigger_type IN ('friend_add', 'tag_added', 'manual')),
  trigger_tag_id  TEXT REFERENCES tags (id) ON DELETE SET NULL,
  is_active       INTEGER NOT NULL DEFAULT 1,
  delivery_mode   TEXT NOT NULL DEFAULT 'relative' CHECK (delivery_mode IN ('relative', 'elapsed', 'absolute_time')),
  created_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

-- ============================================================
-- Scenario Steps
-- ============================================================
CREATE TABLE IF NOT EXISTS scenario_steps (
  id              TEXT PRIMARY KEY,
  scenario_id     TEXT NOT NULL REFERENCES scenarios (id) ON DELETE CASCADE,
  step_order      INTEGER NOT NULL,
  delay_minutes   INTEGER NOT NULL DEFAULT 0,
  message_type    TEXT NOT NULL CHECK (message_type IN ('text', 'image', 'flex')),
  message_content TEXT NOT NULL,
  offset_days     INTEGER,
  offset_minutes  INTEGER,
  delivery_time   TEXT,
  template_id     TEXT REFERENCES templates(id) ON DELETE SET NULL,
  on_reach_tag_id TEXT REFERENCES tags(id) ON DELETE SET NULL,
  created_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  UNIQUE (scenario_id, step_order)
);

CREATE INDEX IF NOT EXISTS idx_scenario_steps_scenario_id ON scenario_steps (scenario_id);

-- ============================================================
-- Friend Scenario Enrollments
-- ============================================================
CREATE TABLE IF NOT EXISTS friend_scenarios (
  id                 TEXT PRIMARY KEY,
  friend_id          TEXT NOT NULL REFERENCES friends (id) ON DELETE CASCADE,
  scenario_id        TEXT NOT NULL REFERENCES scenarios (id) ON DELETE CASCADE,
  current_step_order INTEGER NOT NULL DEFAULT 0,
  status             TEXT NOT NULL CHECK (status IN ('active', 'paused', 'completed', 'delivering')) DEFAULT 'active',
  started_at         TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  next_delivery_at   TEXT,
  updated_at         TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_friend_scenarios_next_delivery_at ON friend_scenarios (next_delivery_at);
CREATE INDEX IF NOT EXISTS idx_friend_scenarios_status ON friend_scenarios (status);
CREATE INDEX IF NOT EXISTS idx_friend_scenarios_friend_id ON friend_scenarios (friend_id);
CREATE UNIQUE INDEX IF NOT EXISTS idx_friend_scenarios_unique ON friend_scenarios (friend_id, scenario_id) WHERE status != 'completed';

-- ============================================================
-- Broadcasts
-- ============================================================
CREATE TABLE IF NOT EXISTS broadcasts (
  id              TEXT PRIMARY KEY,
  title           TEXT NOT NULL,
  message_type    TEXT NOT NULL CHECK (message_type IN ('text', 'image', 'flex', 'video', 'audio', 'sticker', 'imagemap', 'richvideo')),
  message_content TEXT NOT NULL,
  target_type     TEXT NOT NULL CHECK (target_type IN ('all', 'tag', 'segment', 'multi-account-dedup')) DEFAULT 'all',
  target_tag_id   TEXT REFERENCES tags (id) ON DELETE SET NULL,
  status          TEXT NOT NULL CHECK (status IN ('draft', 'scheduled', 'sending', 'sent')) DEFAULT 'draft',
  scheduled_at    TEXT,
  sent_at         TEXT,
  total_count     INTEGER NOT NULL DEFAULT 0,
  success_count   INTEGER NOT NULL DEFAULT 0,
  line_request_id   TEXT,
  aggregation_unit  TEXT,
  batch_offset    INTEGER NOT NULL DEFAULT 0,
  segment_conditions TEXT,
  created_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  account_ids        TEXT CHECK (account_ids IS NULL OR json_valid(account_ids)),
  dedup_priority     TEXT CHECK (dedup_priority IS NULL OR json_valid(dedup_priority)),
  failed_account_ids TEXT CHECK (failed_account_ids IS NULL OR json_valid(failed_account_ids)),
  dedup_progress     TEXT CHECK (dedup_progress IS NULL OR json_valid(dedup_progress)),
  batch_lock_at      TEXT,
  sender_preset_id   TEXT REFERENCES sender_presets (id) ON DELETE SET NULL,
  ab_test_id         TEXT REFERENCES ab_tests (id) ON DELETE SET NULL,
  ab_variant         TEXT,
  messages           TEXT
);

CREATE INDEX IF NOT EXISTS idx_broadcasts_status ON broadcasts (status);
CREATE INDEX IF NOT EXISTS idx_broadcasts_ab_test_id ON broadcasts (ab_test_id);

-- ============================================================
--- Account Settings
--- ============================================================
CREATE TABLE IF NOT EXISTS account_settings (
  id              TEXT PRIMARY KEY,
  line_account_id TEXT NOT NULL,
  key             TEXT NOT NULL,
  value           TEXT NOT NULL,
  created_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  UNIQUE(line_account_id, key)
);

-- ============================================================
-- Broadcast Insights
-- ============================================================
CREATE TABLE IF NOT EXISTS broadcast_insights (
  id                  TEXT PRIMARY KEY,
  broadcast_id        TEXT NOT NULL REFERENCES broadcasts(id) ON DELETE CASCADE,
  delivered           INTEGER,
  unique_impression   INTEGER,
  unique_click        INTEGER,
  unique_media_played INTEGER,
  open_rate           REAL,
  click_rate          REAL,
  raw_response        TEXT,
  status              TEXT NOT NULL CHECK (status IN ('pending', 'ready', 'failed')),
  retry_count         INTEGER NOT NULL DEFAULT 0,
  fetched_at          TEXT,
  created_at          TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_broadcast_insights_broadcast_id ON broadcast_insights(broadcast_id);
CREATE INDEX IF NOT EXISTS idx_broadcast_insights_status ON broadcast_insights(status);

-- ============================================================
-- Messages Log
-- ============================================================
CREATE TABLE IF NOT EXISTS messages_log (
  id               TEXT PRIMARY KEY,
  friend_id        TEXT NOT NULL REFERENCES friends (id) ON DELETE CASCADE,
  direction        TEXT NOT NULL CHECK (direction IN ('incoming', 'outgoing')),
  message_type     TEXT NOT NULL,
  content          TEXT NOT NULL,
  broadcast_id     TEXT REFERENCES broadcasts (id) ON DELETE SET NULL,
  scenario_step_id TEXT REFERENCES scenario_steps (id) ON DELETE SET NULL,
  template_id_at_send TEXT,
  delivery_type    TEXT CHECK (delivery_type IN ('push', 'reply', 'test')),
  source           TEXT,
  line_account_id  TEXT,
  created_at       TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_messages_log_broadcast_id ON messages_log(broadcast_id);

CREATE INDEX IF NOT EXISTS idx_messages_log_friend_id ON messages_log (friend_id);
CREATE INDEX IF NOT EXISTS idx_messages_log_created_at ON messages_log (created_at);
CREATE INDEX IF NOT EXISTS idx_messages_log_friend_source ON messages_log (friend_id, source);
CREATE INDEX IF NOT EXISTS idx_messages_log_friend_direction_created ON messages_log (friend_id, direction, created_at);

-- Test-send idempotency claims. A browser-generated operation key is claimed
-- before LINE push, so double clicks and retries cannot deliver twice.
CREATE TABLE IF NOT EXISTS test_send_requests (
  idempotency_key TEXT PRIMARY KEY,
  line_account_id TEXT NOT NULL,
  source           TEXT NOT NULL,
  request_payload  TEXT NOT NULL,
  status           TEXT NOT NULL CHECK (status IN ('processing', 'completed')),
  response_json    TEXT,
  created_at       TEXT NOT NULL,
  completed_at     TEXT
);

CREATE INDEX IF NOT EXISTS idx_test_send_requests_account_created
  ON test_send_requests (line_account_id, created_at);

-- ============================================================
-- Auto Replies
-- ============================================================
CREATE TABLE IF NOT EXISTS auto_replies (
  id               TEXT PRIMARY KEY,
  keyword          TEXT NOT NULL,
  match_type       TEXT NOT NULL CHECK (match_type IN ('exact', 'contains')) DEFAULT 'exact',
  response_type    TEXT NOT NULL DEFAULT 'text',
  response_content TEXT NOT NULL,
  response_messages TEXT,
  template_id      TEXT REFERENCES templates(id) ON DELETE SET NULL,
  line_account_id  TEXT DEFAULT NULL,
  is_active        INTEGER NOT NULL DEFAULT 1,
  created_at       TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_auto_replies_template_id ON auto_replies(template_id);

-- ============================================================
-- FAQs
-- ============================================================
CREATE TABLE IF NOT EXISTS faqs (
  id               TEXT PRIMARY KEY,
  line_account_id  TEXT DEFAULT NULL,
  question         TEXT NOT NULL,
  variants         TEXT NOT NULL DEFAULT '[]',
  answer           TEXT NOT NULL,
  is_active        INTEGER NOT NULL DEFAULT 1,
  hit_count        INTEGER NOT NULL DEFAULT 0,
  created_at       TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f','now','+9 hours')),
  updated_at       TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f','now','+9 hours')),
  answer_type      TEXT DEFAULT 'text',
  source_doc_id    TEXT,
  -- Phase B B-2 (091): アプリ層 (worker faq-fts.ts) が計算する 2-gram 空白連結の全文検索索引列。
  search_text      TEXT NOT NULL DEFAULT ''
  -- Phase B reserved (add with additive ALTER):
  --   embedding   BLOB  (B-4 / Vectorize)
);

CREATE INDEX IF NOT EXISTS idx_faqs_account_active ON faqs(line_account_id, is_active);

-- Phase B B-2 (091): FAQ 全文検索 (FTS5)。standalone 仮想表 + NEW.search_text コピーのみの同期トリガ 3 本。
-- トリガは 1 行 (replay 分割器が BEGIN...END を壊さないため)。shadow 表は SQLite 自動生成の派生物。
CREATE VIRTUAL TABLE IF NOT EXISTS faqs_fts USING fts5(search_text, tokenize='unicode61');
CREATE TRIGGER IF NOT EXISTS faqs_fts_ai AFTER INSERT ON faqs BEGIN INSERT INTO faqs_fts(rowid, search_text) VALUES (NEW.rowid, NEW.search_text); END;
CREATE TRIGGER IF NOT EXISTS faqs_fts_ad AFTER DELETE ON faqs BEGIN DELETE FROM faqs_fts WHERE rowid = OLD.rowid; END;
CREATE TRIGGER IF NOT EXISTS faqs_fts_au AFTER UPDATE ON faqs BEGIN DELETE FROM faqs_fts WHERE rowid = OLD.rowid; INSERT INTO faqs_fts(rowid, search_text) VALUES (NEW.rowid, NEW.search_text); END;

-- ============================================================
-- Knowledge ingest (Phase B B-3 / 092)
-- ============================================================
-- 取込ナレッジの資料 (documents) + 分割チャンク (chunks) + FTS5 索引。faqs_fts (091) とは別表
-- knowledge_chunks_fts (二重実装なし)。source_doc_id は宣言 FK (D1 は FK off・削除はアプリ側で
-- chunks→document 明示)。search_text はアプリ層 (worker services/knowledge.ts) が計算する索引列。
-- トリガは NEW.search_text コピーのみ (1 行 / replay 分割器が BEGIN...END を壊さない)。
-- shadow 表は SQLite 自動生成の派生物 (generate-bootstrap 汎用除外で bootstrap 対象外)。
CREATE TABLE IF NOT EXISTS knowledge_documents (
  id              TEXT PRIMARY KEY,
  line_account_id TEXT,
  source_type     TEXT NOT NULL,
  source_url      TEXT,
  title           TEXT,
  created_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f','now','+9 hours')),
  updated_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f','now','+9 hours'))
);
CREATE TABLE IF NOT EXISTS knowledge_chunks (
  id              TEXT PRIMARY KEY,
  source_doc_id   TEXT NOT NULL REFERENCES knowledge_documents(id),
  line_account_id TEXT,
  chunk_index     INTEGER NOT NULL,
  content         TEXT NOT NULL,
  search_text     TEXT NOT NULL DEFAULT '',
  created_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f','now','+9 hours')),
  embedded_at     TEXT,
  embed_model     TEXT,
  UNIQUE(source_doc_id, chunk_index)
);
CREATE INDEX IF NOT EXISTS idx_knowledge_chunks_doc ON knowledge_chunks(source_doc_id);
CREATE INDEX IF NOT EXISTS idx_knowledge_chunks_acct ON knowledge_chunks(line_account_id);
CREATE VIRTUAL TABLE IF NOT EXISTS knowledge_chunks_fts USING fts5(search_text, tokenize='unicode61');
CREATE TRIGGER IF NOT EXISTS knowledge_chunks_fts_ai AFTER INSERT ON knowledge_chunks BEGIN INSERT INTO knowledge_chunks_fts(rowid, search_text) VALUES (NEW.rowid, NEW.search_text); END;
CREATE TRIGGER IF NOT EXISTS knowledge_chunks_fts_ad AFTER DELETE ON knowledge_chunks BEGIN DELETE FROM knowledge_chunks_fts WHERE rowid = OLD.rowid; END;
CREATE TRIGGER IF NOT EXISTS knowledge_chunks_fts_au AFTER UPDATE ON knowledge_chunks BEGIN DELETE FROM knowledge_chunks_fts WHERE rowid = OLD.rowid; INSERT INTO knowledge_chunks_fts(rowid, search_text) VALUES (NEW.rowid, NEW.search_text); END;

-- ============================================================
-- AI FAQ drafts (Phase B B-1 / answer_mode=draft の草案保存)
-- ============================================================
CREATE TABLE IF NOT EXISTS ai_faq_drafts (
  id                TEXT PRIMARY KEY,
  line_account_id   TEXT,
  friend_id         TEXT,
  question          TEXT NOT NULL,
  draft_answer      TEXT NOT NULL,
  answerable        INTEGER NOT NULL DEFAULT 1 CHECK (answerable IN (0, 1)),
  evidence_faq_ids  TEXT NOT NULL DEFAULT '[]',
  status            TEXT NOT NULL DEFAULT 'pending',
  created_at        TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f','now','+9 hours')),
  updated_at        TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f','now','+9 hours'))
);
CREATE INDEX IF NOT EXISTS idx_ai_faq_drafts_account_status ON ai_faq_drafts(line_account_id, status);

-- Operator review audit for AI FAQ drafts (migration 123). Values are not copied here;
-- the draft/messages_log rows remain the content records and this table records who did what.
CREATE TABLE IF NOT EXISTS ai_faq_draft_audit_log (
  id              TEXT PRIMARY KEY,
  draft_id        TEXT NOT NULL REFERENCES ai_faq_drafts(id) ON DELETE RESTRICT,
  line_account_id TEXT,
  friend_id       TEXT NOT NULL,
  actor_staff_id  TEXT NOT NULL,
  action          TEXT NOT NULL CHECK (action IN ('edited', 'approved', 'discarded', 'send_failed')),
  created_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_ai_faq_draft_audit_draft_created
  ON ai_faq_draft_audit_log (draft_id, created_at);

CREATE INDEX IF NOT EXISTS idx_ai_faq_draft_audit_account_created
  ON ai_faq_draft_audit_log (line_account_id, created_at);

CREATE TRIGGER IF NOT EXISTS trg_ai_faq_draft_audit_no_replace
BEFORE INSERT ON ai_faq_draft_audit_log
WHEN EXISTS (SELECT 1 FROM ai_faq_draft_audit_log WHERE id = NEW.id)
BEGIN SELECT RAISE(ABORT, 'ai_faq_draft_audit_log is append-only'); END;

CREATE TRIGGER IF NOT EXISTS trg_ai_faq_draft_audit_no_update
BEFORE UPDATE ON ai_faq_draft_audit_log
BEGIN SELECT RAISE(ABORT, 'ai_faq_draft_audit_log is append-only'); END;

CREATE TRIGGER IF NOT EXISTS trg_ai_faq_draft_audit_no_delete
BEFORE DELETE ON ai_faq_draft_audit_log
BEGIN SELECT RAISE(ABORT, 'ai_faq_draft_audit_log is append-only'); END;

-- FAQ AI personal-context injection audit (migration 122).
-- Values are never stored: only source/category metadata needed for an audit trail.
CREATE TABLE IF NOT EXISTS faq_personal_context_audit_log (
  id                         TEXT PRIMARY KEY,
  line_account_id            TEXT NOT NULL,
  friend_id                  TEXT NOT NULL,
  display_name_included      INTEGER NOT NULL DEFAULT 0 CHECK (display_name_included IN (0, 1)),
  custom_field_ids_json      TEXT NOT NULL DEFAULT '[]',
  formaloo_submission_count  INTEGER NOT NULL DEFAULT 0 CHECK (formaloo_submission_count >= 0),
  internal_submission_count  INTEGER NOT NULL DEFAULT 0 CHECK (internal_submission_count >= 0),
  prompt_token_estimate      INTEGER NOT NULL DEFAULT 0 CHECK (prompt_token_estimate >= 0),
  was_truncated              INTEGER NOT NULL DEFAULT 0 CHECK (was_truncated IN (0, 1)),
  created_at                 TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_faq_personal_context_audit_account_created
  ON faq_personal_context_audit_log (line_account_id, created_at);

CREATE INDEX IF NOT EXISTS idx_faq_personal_context_audit_friend_created
  ON faq_personal_context_audit_log (friend_id, created_at);

CREATE TRIGGER IF NOT EXISTS trg_faq_personal_context_audit_no_replace
BEFORE INSERT ON faq_personal_context_audit_log
WHEN EXISTS (SELECT 1 FROM faq_personal_context_audit_log WHERE id = NEW.id)
BEGIN SELECT RAISE(ABORT, 'faq_personal_context_audit_log is append-only'); END;

CREATE TRIGGER IF NOT EXISTS trg_faq_personal_context_audit_no_update
BEFORE UPDATE ON faq_personal_context_audit_log
BEGIN SELECT RAISE(ABORT, 'faq_personal_context_audit_log is append-only'); END;

CREATE TRIGGER IF NOT EXISTS trg_faq_personal_context_audit_no_delete
BEFORE DELETE ON faq_personal_context_audit_log
BEGIN SELECT RAISE(ABORT, 'faq_personal_context_audit_log is append-only'); END;

-- ============================================================
-- AI usage budget (Phase B B-1 / Workers AI 無料枠の UTC 日 neuron 積算)
-- ============================================================
CREATE TABLE IF NOT EXISTS ai_usage_budget (
  id                TEXT PRIMARY KEY,
  line_account_id   TEXT NOT NULL,
  usage_date        TEXT NOT NULL,
  llm_neurons       INTEGER NOT NULL DEFAULT 0,
  embed_neurons     INTEGER NOT NULL DEFAULT 0,
  image_neurons     INTEGER NOT NULL DEFAULT 0,
  reply_count       INTEGER NOT NULL DEFAULT 0,
  created_at        TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f','now','+9 hours')),
  updated_at        TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f','now','+9 hours')),
  UNIQUE(line_account_id, usage_date)
);
CREATE INDEX IF NOT EXISTS idx_ai_usage_budget_date ON ai_usage_budget(usage_date);

CREATE TABLE IF NOT EXISTS unmatched_questions (
  id               TEXT PRIMARY KEY,
  line_account_id  TEXT DEFAULT NULL,
  friend_id        TEXT REFERENCES friends(id) ON DELETE SET NULL,
  question         TEXT NOT NULL,
  top_score        REAL,
  resolved_faq_id  TEXT REFERENCES faqs(id) ON DELETE SET NULL,
  created_at       TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f','now','+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_unmatched_account_created ON unmatched_questions(line_account_id, created_at);

-- ============================================================
-- Admin Users
-- ============================================================
CREATE TABLE IF NOT EXISTS admin_users (
  id            TEXT PRIMARY KEY,
  email         TEXT NOT NULL UNIQUE,
  password_hash TEXT NOT NULL,
  created_at    TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

-- ============================================================
-- Round 2: Internal UUID Users (Cross-Account)
-- ============================================================
CREATE TABLE IF NOT EXISTS users (
  id           TEXT PRIMARY KEY,
  email        TEXT,
  phone        TEXT,
  external_id  TEXT,
  display_name TEXT,
  created_at   TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at   TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_users_email ON users (email);
CREATE INDEX IF NOT EXISTS idx_users_phone ON users (phone);
CREATE INDEX IF NOT EXISTS idx_users_external_id ON users (external_id);

-- ============================================================
-- Round 2: LINE Account Management (Multi-Account)
-- ============================================================
CREATE TABLE IF NOT EXISTS line_accounts (
  id                   TEXT PRIMARY KEY,
  channel_id           TEXT NOT NULL UNIQUE,
  name                 TEXT NOT NULL,
  channel_access_token TEXT NOT NULL,
  channel_secret       TEXT NOT NULL,
  is_active            INTEGER NOT NULL DEFAULT 1,
  country              TEXT,
  role                 TEXT,
  display_order        INTEGER NOT NULL DEFAULT 0,
  created_at           TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at           TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  -- monthly_cap (migration 057 / F2 batch4 G2): 月次送信上限 (NULL = 無制限 = 既定挙動不変)。
  monthly_cap          INTEGER
);

CREATE INDEX IF NOT EXISTS idx_line_accounts_display_order
  ON line_accounts (display_order, created_at);

-- ============================================================
-- Existing follower import (migration 122)
-- ============================================================
CREATE TABLE IF NOT EXISTS friend_import_jobs (
  id                      TEXT PRIMARY KEY,
  account_id              TEXT NOT NULL,
  status                  TEXT NOT NULL DEFAULT 'running'
                          CHECK (status IN ('running', 'completed', 'failed')),
  phase                   TEXT NOT NULL DEFAULT 'followers'
                          CHECK (phase IN ('followers', 'profiles', 'completed')),
  continuation_token      TEXT,
  fetched_count           INTEGER NOT NULL DEFAULT 0 CHECK (fetched_count >= 0),
  new_count               INTEGER NOT NULL DEFAULT 0 CHECK (new_count >= 0),
  existing_count          INTEGER NOT NULL DEFAULT 0 CHECK (existing_count >= 0),
  profile_processed_count INTEGER NOT NULL DEFAULT 0 CHECK (profile_processed_count >= 0),
  failed_count            INTEGER NOT NULL DEFAULT 0 CHECK (failed_count >= 0),
  next_run_at             TEXT,
  lock_token              TEXT,
  locked_until            TEXT,
  last_error_code         TEXT,
  last_error              TEXT,
  requested_by_id         TEXT NOT NULL,
  requested_by_name       TEXT NOT NULL,
  created_at              TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at              TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  completed_at            TEXT
);

CREATE UNIQUE INDEX IF NOT EXISTS idx_friend_import_jobs_one_running
  ON friend_import_jobs (account_id) WHERE status = 'running';
CREATE INDEX IF NOT EXISTS idx_friend_import_jobs_latest
  ON friend_import_jobs (account_id, created_at DESC, id DESC);

CREATE TABLE IF NOT EXISTS friend_import_items (
  job_id         TEXT NOT NULL REFERENCES friend_import_jobs (id) ON DELETE CASCADE,
  line_user_id   TEXT NOT NULL,
  friend_id      TEXT NOT NULL,
  outcome        TEXT NOT NULL CHECK (outcome IN ('new', 'existing', 'conflict')),
  profile_status TEXT NOT NULL CHECK (profile_status IN ('pending', 'succeeded', 'failed', 'not_required')),
  profile_attempts INTEGER NOT NULL DEFAULT 0 CHECK (profile_attempts >= 0),
  next_attempt_at TEXT,
  error_message  TEXT,
  created_at     TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at     TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  PRIMARY KEY (job_id, line_user_id)
);

CREATE INDEX IF NOT EXISTS idx_friend_import_items_profiles
  ON friend_import_items (job_id, outcome, profile_status, next_attempt_at, line_user_id);

CREATE TABLE IF NOT EXISTS friend_import_audit_log (
  id              TEXT PRIMARY KEY,
  job_id          TEXT NOT NULL REFERENCES friend_import_jobs (id) ON DELETE RESTRICT,
  account_id      TEXT NOT NULL,
  event_type      TEXT NOT NULL,
  actor_id        TEXT NOT NULL,
  actor_name      TEXT NOT NULL,
  new_count       INTEGER NOT NULL CHECK (new_count >= 0),
  existing_count  INTEGER NOT NULL CHECK (existing_count >= 0),
  failed_count    INTEGER NOT NULL CHECK (failed_count >= 0),
  detail          TEXT,
  created_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_friend_import_audit_account
  ON friend_import_audit_log (account_id, created_at DESC, id DESC);
CREATE INDEX IF NOT EXISTS idx_friend_import_audit_job
  ON friend_import_audit_log (job_id, created_at, id);

CREATE TRIGGER IF NOT EXISTS trg_friend_import_audit_no_update BEFORE UPDATE ON friend_import_audit_log BEGIN SELECT RAISE(ABORT, 'friend_import_audit_log is append-only'); END;
CREATE TRIGGER IF NOT EXISTS trg_friend_import_audit_no_delete BEFORE DELETE ON friend_import_audit_log BEGIN SELECT RAISE(ABORT, 'friend_import_audit_log is append-only'); END;

-- ============================================================
-- Self-hosted Google Sheets connections (migration 114)
-- Connection settings are independent of migration 113/W1. form_id is an
-- opaque application identifier until the internal-forms schema is available.
-- ============================================================
CREATE TABLE IF NOT EXISTS sheets_connections (
  id              TEXT PRIMARY KEY,
  -- Keep the connection/audit chain when an account is removed. The orphan
  -- trigger below deactivates the setting so it can never be synchronized.
  line_account_id TEXT REFERENCES line_accounts (id) ON DELETE SET NULL,
  form_id         TEXT NOT NULL CHECK (length(form_id) BETWEEN 1 AND 200),
  spreadsheet_id  TEXT NOT NULL CHECK (length(spreadsheet_id) BETWEEN 1 AND 512),
  sheet_name      TEXT NOT NULL DEFAULT 'Sheet1' CHECK (length(sheet_name) BETWEEN 1 AND 200),
  sync_direction  TEXT NOT NULL DEFAULT 'bidirectional'
                  CHECK (sync_direction IN ('to_sheets', 'from_sheets', 'bidirectional')),
  conflict_policy TEXT NOT NULL DEFAULT 'last_write_wins'
                  CHECK (conflict_policy = 'last_write_wins'),
  -- LWW is ordered by a Worker-assigned sequence when a write is accepted.
  -- Sheets values.get exposes no trustworthy human-edit timestamp, so wall-clock
  -- observation time is deliberately not the conflict clock.
  conflict_clock  TEXT NOT NULL DEFAULT 'server_sequence'
                  CHECK (conflict_clock = 'server_sequence'),
  config_version  INTEGER NOT NULL DEFAULT 1 CHECK (config_version >= 1),
  next_sync_sequence INTEGER NOT NULL DEFAULT 1 CHECK (next_sync_sequence >= 1),
  friend_field_mappings_json TEXT NOT NULL DEFAULT '[]'
                  CHECK (json_valid(friend_field_mappings_json) AND json_type(friend_field_mappings_json) = 'array'),
  friend_ledger_enabled INTEGER NOT NULL DEFAULT 0 CHECK (friend_ledger_enabled IN (0, 1)),
  friend_ledger_headers_json TEXT NOT NULL DEFAULT '[]'
                  CHECK (json_valid(friend_ledger_headers_json) AND json_type(friend_ledger_headers_json) = 'array'),
  form_answer_headers_json TEXT NOT NULL DEFAULT '[]'
                  CHECK (json_valid(form_answer_headers_json) AND json_type(form_answer_headers_json) = 'array'),
  -- Separate form-results tab (migration 127). Default 0 keeps the legacy
  -- combined-sheet layout until the owner flips the new toggle.
  form_results_enabled INTEGER NOT NULL DEFAULT 0 CHECK (form_results_enabled IN (0, 1)),
  form_results_sheet_name TEXT,
  form_results_headers_json TEXT NOT NULL DEFAULT '[]'
                  CHECK (json_valid(form_results_headers_json) AND json_type(form_results_headers_json) = 'array'),
  -- NULL keeps pre-125 connections on the legacy all-form-fields behavior.
  -- A JSON array stores an explicit selection; [] intentionally selects none.
  selected_form_field_ids_json TEXT
                  CHECK (
                    selected_form_field_ids_json IS NULL
                    OR (
                      json_valid(selected_form_field_ids_json)
                      AND json_type(selected_form_field_ids_json) = 'array'
                    )
                  ),
  last_sync_at    TEXT,
  last_sync_status TEXT NOT NULL DEFAULT 'idle'
                  CHECK (last_sync_status IN ('idle', 'running', 'success', 'warning', 'error')),
  last_sync_warning TEXT,
  last_sync_error_code TEXT,
  form_results_row_shifted_at TEXT,
  form_results_row_shift_pending_until TEXT,
  sync_lock_token TEXT,
  sync_lock_expires_at TEXT,
  is_active       INTEGER NOT NULL DEFAULT 1 CHECK (is_active IN (0, 1)),
  created_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  deleted_at      TEXT
);

CREATE UNIQUE INDEX IF NOT EXISTS idx_sheets_connections_active_form
  ON sheets_connections (line_account_id, form_id)
  WHERE is_active = 1 AND deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_sheets_connections_account
  ON sheets_connections (line_account_id, is_active, updated_at);

CREATE TRIGGER IF NOT EXISTS trg_sheets_connections_orphan_deactivate
AFTER UPDATE OF line_account_id ON sheets_connections
WHEN NEW.line_account_id IS NULL AND NEW.is_active = 1
BEGIN DELETE FROM sheets_sync_ledger WHERE connection_id = NEW.id; UPDATE sheets_connections SET is_active = 0, deleted_at = COALESCE(deleted_at, strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')), updated_at = strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours') WHERE id = NEW.id; END;

-- One durable fingerprint per Harness record. This is only the ledger/data
-- shape; the polling/apply engine is deliberately deferred to W4 proper.
CREATE TABLE IF NOT EXISTS sheets_sync_ledger (
  connection_id      TEXT NOT NULL REFERENCES sheets_connections (id) ON DELETE CASCADE,
  connection_version INTEGER NOT NULL DEFAULT 1 CHECK (connection_version >= 1),
  record_key         TEXT NOT NULL CHECK (length(record_key) BETWEEN 1 AND 200),
  sheet_row_number   INTEGER CHECK (sheet_row_number IS NULL OR sheet_row_number >= 1),
  row_fingerprint    TEXT NOT NULL CHECK (length(row_fingerprint) BETWEEN 1 AND 256),
  harness_updated_at TEXT,
  -- API observation time is diagnostic only and is never used as the conflict clock.
  sheet_observed_at  TEXT,
  last_synced_at     TEXT NOT NULL,
  last_sync_direction TEXT NOT NULL CHECK (last_sync_direction IN ('to_sheets', 'from_sheets')),
  last_applied_sequence INTEGER NOT NULL CHECK (last_applied_sequence >= 1),
  version            INTEGER NOT NULL DEFAULT 1 CHECK (version >= 1),
  canonical_snapshot_json TEXT NOT NULL DEFAULT '{}'
                     CHECK (json_valid(canonical_snapshot_json) AND json_type(canonical_snapshot_json) = 'object'),
  PRIMARY KEY (connection_id, record_key)
);

-- Row-number slots are unique per target: the ledger tab and the results tab
-- of the same connection may both use sheet row N (migration 127).
CREATE UNIQUE INDEX IF NOT EXISTS idx_sheets_sync_ledger_row_ledger
  ON sheets_sync_ledger (connection_id, sheet_row_number)
  WHERE sheet_row_number IS NOT NULL AND record_key NOT LIKE 'sub:%';
CREATE UNIQUE INDEX IF NOT EXISTS idx_sheets_sync_ledger_row_form_results
  ON sheets_sync_ledger (connection_id, sheet_row_number)
  WHERE sheet_row_number IS NOT NULL AND record_key LIKE 'sub:%';

-- A delayed worker from an old configuration generation must fail closed.
CREATE TRIGGER IF NOT EXISTS trg_sheets_sync_ledger_version_insert
BEFORE INSERT ON sheets_sync_ledger
WHEN NOT EXISTS (SELECT 1 FROM sheets_connections WHERE id = NEW.connection_id AND config_version = NEW.connection_version AND is_active = 1 AND deleted_at IS NULL)
BEGIN SELECT RAISE(ABORT, 'sheets_sync_ledger connection version mismatch'); END;

CREATE TRIGGER IF NOT EXISTS trg_sheets_sync_ledger_version_update
BEFORE UPDATE ON sheets_sync_ledger
WHEN NOT EXISTS (SELECT 1 FROM sheets_connections WHERE id = NEW.connection_id AND config_version = NEW.connection_version AND is_active = 1 AND deleted_at IS NULL)
BEGIN SELECT RAISE(ABORT, 'sheets_sync_ledger connection version mismatch'); END;

-- Append-only audit events. No updated_at column is intentional: conflict
-- decisions remain immutable evidence for last-write-wins reconciliation.
CREATE TABLE IF NOT EXISTS sheets_sync_audit_log (
  id                   TEXT PRIMARY KEY,
  connection_id        TEXT NOT NULL REFERENCES sheets_connections (id) ON DELETE RESTRICT,
  connection_version   INTEGER NOT NULL CHECK (connection_version >= 1),
  apply_sequence       INTEGER NOT NULL CHECK (apply_sequence >= 1),
  -- Immutable target snapshot: later connection edits cannot rewrite history.
  line_account_id      TEXT NOT NULL,
  form_id              TEXT NOT NULL,
  spreadsheet_id       TEXT NOT NULL,
  sheet_name           TEXT NOT NULL,
  record_key           TEXT,
  sheet_row_number      INTEGER CHECK (sheet_row_number IS NULL OR sheet_row_number >= 1),
  direction             TEXT NOT NULL CHECK (direction IN ('to_sheets', 'from_sheets')),
  action                TEXT NOT NULL CHECK (action IN ('append', 'read', 'update', 'conflict')),
  outcome               TEXT NOT NULL CHECK (outcome IN ('applied', 'skipped', 'failed')),
  conflict_resolution   TEXT CHECK (
    conflict_resolution IS NULL OR conflict_resolution IN ('harness_wins', 'sheet_wins', 'same_sequence')
  ),
  harness_updated_at    TEXT,
  sheet_observed_at     TEXT,
  before_fingerprint   TEXT,
  after_fingerprint    TEXT,
  error_code            TEXT,
  webhook_event_id      TEXT,
  created_at            TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_sheets_sync_audit_connection
  ON sheets_sync_audit_log (connection_id, created_at);
CREATE UNIQUE INDEX IF NOT EXISTS idx_sheets_sync_audit_sequence
  ON sheets_sync_audit_log (connection_id, connection_version, apply_sequence);
CREATE UNIQUE INDEX IF NOT EXISTS idx_sheets_sync_audit_webhook_event
  ON sheets_sync_audit_log (connection_id, webhook_event_id)
  WHERE webhook_event_id IS NOT NULL;

CREATE TRIGGER IF NOT EXISTS trg_sheets_sync_audit_no_replace
BEFORE INSERT ON sheets_sync_audit_log
WHEN EXISTS (SELECT 1 FROM sheets_sync_audit_log WHERE id = NEW.id)
  OR EXISTS (
    SELECT 1 FROM sheets_sync_audit_log
    WHERE connection_id = NEW.connection_id
      AND connection_version = NEW.connection_version
      AND apply_sequence = NEW.apply_sequence
  )
BEGIN SELECT RAISE(ABORT, 'sheets_sync_audit_log is append-only'); END;

CREATE TRIGGER IF NOT EXISTS trg_sheets_sync_audit_no_update
BEFORE UPDATE ON sheets_sync_audit_log
BEGIN SELECT RAISE(ABORT, 'sheets_sync_audit_log is append-only'); END;

CREATE TRIGGER IF NOT EXISTS trg_sheets_sync_audit_no_delete
BEFORE DELETE ON sheets_sync_audit_log
BEGIN SELECT RAISE(ABORT, 'sheets_sync_audit_log is append-only'); END;

CREATE TABLE IF NOT EXISTS sheets_sync_audit_details (
  id          TEXT PRIMARY KEY,
  audit_id    TEXT NOT NULL REFERENCES sheets_sync_audit_log (id) ON DELETE RESTRICT,
  actor       TEXT NOT NULL CHECK (length(actor) BETWEEN 1 AND 320),
  column_name TEXT NOT NULL CHECK (length(column_name) BETWEEN 1 AND 200),
  old_value   TEXT,
  new_value   TEXT,
  source      TEXT NOT NULL CHECK (source IN ('webhook', 'polling', 'manual')),
  change_kind TEXT NOT NULL CHECK (change_kind IN ('custom_field', 'identity_sync', 'identity_ignored', 'conflict')),
  created_at  TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_sheets_sync_audit_details_parent
  ON sheets_sync_audit_details (audit_id, created_at, id);

CREATE TABLE IF NOT EXISTS sheets_sync_webhook_events (
  sequence           INTEGER PRIMARY KEY AUTOINCREMENT,
  connection_id      TEXT NOT NULL REFERENCES sheets_connections (id) ON DELETE CASCADE,
  line_account_id    TEXT NOT NULL REFERENCES line_accounts (id) ON DELETE CASCADE,
  connection_version INTEGER NOT NULL CHECK (connection_version >= 1),
  -- Which sync target the edited tab belongs to (migration 127).
  target              TEXT NOT NULL DEFAULT 'ledger' CHECK (target IN ('ledger', 'form_results')),
  event_id            TEXT NOT NULL CHECK (length(event_id) BETWEEN 16 AND 200),
  actor               TEXT NOT NULL CHECK (length(actor) BETWEEN 1 AND 320),
  actor_kind          TEXT NOT NULL CHECK (actor_kind IN ('google_email', 'unavailable')),
  occurred_at         TEXT NOT NULL,
  payload_json        TEXT CHECK (payload_json IS NULL OR (json_valid(payload_json) AND json_type(payload_json) = 'object')),
  status              TEXT NOT NULL DEFAULT 'pending' CHECK (status IN ('pending', 'applied', 'dead')),
  attempts            INTEGER NOT NULL DEFAULT 0 CHECK (attempts >= 0),
  available_at        TEXT NOT NULL,
  processing_token    TEXT,
  processing_expires_at TEXT,
  received_at         TEXT NOT NULL,
  completed_at        TEXT,
  last_error_code     TEXT,
  created_at          TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  UNIQUE (connection_id, event_id),
  CHECK ((processing_token IS NULL) = (processing_expires_at IS NULL)),
  CHECK (processing_token IS NULL OR length(processing_token) BETWEEN 8 AND 200),
  CHECK (julianday(occurred_at) IS NOT NULL),
  CHECK (julianday(available_at) IS NOT NULL),
  CHECK (julianday(received_at) IS NOT NULL),
  CHECK (processing_expires_at IS NULL OR julianday(processing_expires_at) IS NOT NULL),
  CHECK (completed_at IS NULL OR julianday(completed_at) IS NOT NULL),
  CHECK (
    (status = 'pending' AND payload_json IS NOT NULL AND completed_at IS NULL)
    OR
    (status IN ('applied', 'dead') AND payload_json IS NULL
      AND processing_token IS NULL AND completed_at IS NOT NULL
      AND actor = 'redacted' AND actor_kind = 'unavailable')
  )
);

-- Durable progress for bounded friend-ledger synchronization (migration 126).
CREATE TABLE IF NOT EXISTS sheets_sync_jobs (
  id                         TEXT PRIMARY KEY,
  connection_id              TEXT NOT NULL REFERENCES sheets_connections (id) ON DELETE RESTRICT,
  line_account_id            TEXT NOT NULL REFERENCES line_accounts (id) ON DELETE CASCADE,
  config_version             INTEGER NOT NULL CHECK (config_version >= 1),
  source                     TEXT NOT NULL CHECK (source IN ('manual', 'polling', 'webhook')),
  actor                      TEXT NOT NULL CHECK (length(actor) BETWEEN 1 AND 320),
  status                     TEXT NOT NULL DEFAULT 'running'
                             CHECK (status IN ('running', 'completed', 'warning', 'failed')),
  total_count                INTEGER NOT NULL DEFAULT 0 CHECK (total_count >= 0),
  processed_count            INTEGER NOT NULL DEFAULT 0
                             CHECK (processed_count >= 0 AND processed_count <= total_count),
  last_friend_created_at     TEXT,
  last_record_key            TEXT,
  snapshot_friend_created_at TEXT,
  snapshot_record_key        TEXT,
  appended_rows              INTEGER NOT NULL DEFAULT 0 CHECK (appended_rows >= 0),
  updated_rows               INTEGER NOT NULL DEFAULT 0 CHECK (updated_rows >= 0),
  imported_fields            INTEGER NOT NULL DEFAULT 0 CHECK (imported_fields >= 0),
  ignored_identity_edits     INTEGER NOT NULL DEFAULT 0 CHECK (ignored_identity_edits >= 0),
  warning_message            TEXT CHECK (warning_message IS NULL OR length(warning_message) <= 500),
  error_code                 TEXT CHECK (error_code IS NULL OR length(error_code) <= 100),
  error_message              TEXT CHECK (error_message IS NULL OR length(error_message) <= 500),
  lock_token                 TEXT,
  locked_until               TEXT,
  created_at                 TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at                 TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  completed_at               TEXT,
  -- Which sync target the job advances (migration 128).
  target                     TEXT NOT NULL DEFAULT 'ledger' CHECK (target IN ('ledger', 'form_results')),
  CHECK ((lock_token IS NULL) = (locked_until IS NULL)),
  CHECK ((snapshot_friend_created_at IS NULL) = (snapshot_record_key IS NULL))
);

CREATE UNIQUE INDEX IF NOT EXISTS idx_sheets_sync_jobs_one_running
  ON sheets_sync_jobs (connection_id, target)
  WHERE status = 'running';

CREATE INDEX IF NOT EXISTS idx_sheets_sync_jobs_runnable
  ON sheets_sync_jobs (status, locked_until, created_at, id);

CREATE INDEX IF NOT EXISTS idx_sheets_sync_jobs_connection_history
  ON sheets_sync_jobs (line_account_id, connection_id, created_at DESC, id DESC);

CREATE INDEX IF NOT EXISTS idx_sheets_sync_webhook_events_pending
  ON sheets_sync_webhook_events
     (line_account_id, connection_id, status, available_at, sequence);

CREATE INDEX IF NOT EXISTS idx_sheets_sync_webhook_events_lifecycle
  ON sheets_sync_webhook_events (status, received_at, sequence);

CREATE INDEX IF NOT EXISTS idx_sheets_sync_webhook_events_terminal
  ON sheets_sync_webhook_events (status, completed_at, sequence);

CREATE TRIGGER IF NOT EXISTS trg_sheets_sync_ledger_connection_changed
AFTER UPDATE OF config_version, spreadsheet_id, sheet_name, form_results_sheet_name, friend_ledger_enabled, form_results_enabled ON sheets_connections
WHEN NEW.config_version <> OLD.config_version
  OR NEW.friend_ledger_enabled <> OLD.friend_ledger_enabled
  OR NEW.form_results_enabled <> OLD.form_results_enabled
BEGIN DELETE FROM sheets_sync_ledger WHERE connection_id = NEW.id AND record_key NOT LIKE 'sub:%' AND (NEW.spreadsheet_id <> OLD.spreadsheet_id OR NEW.sheet_name <> OLD.sheet_name OR NEW.friend_ledger_enabled <> OLD.friend_ledger_enabled); DELETE FROM sheets_sync_ledger WHERE connection_id = NEW.id AND record_key LIKE 'sub:%' AND (NEW.spreadsheet_id <> OLD.spreadsheet_id OR NEW.form_results_sheet_name IS NOT OLD.form_results_sheet_name OR NEW.form_results_enabled <> OLD.form_results_enabled); UPDATE sheets_sync_ledger SET connection_version = NEW.config_version, version = version + 1 WHERE connection_id = NEW.id AND NEW.config_version <> OLD.config_version; END;

CREATE TRIGGER IF NOT EXISTS trg_sheets_sync_webhook_events_connection_changed
AFTER UPDATE OF config_version, friend_ledger_enabled, form_results_enabled, is_active, deleted_at, line_account_id
ON sheets_connections
WHEN NEW.config_version <> OLD.config_version
  OR NEW.friend_ledger_enabled <> OLD.friend_ledger_enabled
  OR NEW.form_results_enabled <> OLD.form_results_enabled
  OR NEW.is_active <> OLD.is_active
  OR NEW.deleted_at IS NOT OLD.deleted_at
  OR NEW.line_account_id IS NOT OLD.line_account_id
BEGIN
  UPDATE sheets_sync_webhook_events
  SET status = 'dead', payload_json = NULL, actor = 'redacted', actor_kind = 'unavailable',
      processing_token = NULL, processing_expires_at = NULL,
      completed_at = strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'),
      last_error_code = 'connection_changed'
  WHERE connection_id = NEW.id AND status = 'pending'
    AND (
      NEW.config_version <> OLD.config_version
      OR NEW.is_active <> OLD.is_active
      OR NEW.deleted_at IS NOT OLD.deleted_at
      OR NEW.line_account_id IS NOT OLD.line_account_id
      OR (target = 'ledger' AND NEW.friend_ledger_enabled <> OLD.friend_ledger_enabled)
      OR (target = 'form_results' AND NEW.form_results_enabled <> OLD.form_results_enabled)
    ); END;

CREATE TRIGGER IF NOT EXISTS trg_sheets_sync_audit_details_no_replace
BEFORE INSERT ON sheets_sync_audit_details
WHEN EXISTS (SELECT 1 FROM sheets_sync_audit_details WHERE id = NEW.id)
BEGIN SELECT RAISE(ABORT, 'sheets_sync_audit_details is append-only'); END;

CREATE TRIGGER IF NOT EXISTS trg_sheets_sync_audit_details_no_update
BEFORE UPDATE ON sheets_sync_audit_details
BEGIN SELECT RAISE(ABORT, 'sheets_sync_audit_details is append-only'); END;

CREATE TRIGGER IF NOT EXISTS trg_sheets_sync_audit_details_no_delete
BEFORE DELETE ON sheets_sync_audit_details
BEGIN SELECT RAISE(ABORT, 'sheets_sync_audit_details is append-only'); END;

-- ============================================================
-- Tenant-scoped friend field definitions (migration 105)
-- ============================================================
CREATE TABLE IF NOT EXISTS friend_field_definitions (
  id            TEXT PRIMARY KEY,
  name          TEXT NOT NULL,
  default_value TEXT NOT NULL DEFAULT '',
  display_order INTEGER NOT NULL DEFAULT 0,
  is_active     INTEGER NOT NULL DEFAULT 1 CHECK (is_active IN (0, 1)),
  created_at    TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at    TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE UNIQUE INDEX IF NOT EXISTS idx_friend_field_definitions_name
  ON friend_field_definitions (name);

CREATE INDEX IF NOT EXISTS idx_friend_field_definitions_active_order
  ON friend_field_definitions (is_active, display_order, id);

-- ============================================================
-- Round 2: Conversion Points (CV Tracking)
-- ============================================================
CREATE TABLE IF NOT EXISTS conversion_points (
  id         TEXT PRIMARY KEY,
  name       TEXT NOT NULL,
  event_type TEXT NOT NULL,
  value      REAL,
  created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

-- ============================================================
-- Round 2: Conversion Events (CV Records)
-- ============================================================
CREATE TABLE IF NOT EXISTS conversion_events (
  id                  TEXT PRIMARY KEY,
  conversion_point_id TEXT NOT NULL REFERENCES conversion_points (id) ON DELETE CASCADE,
  friend_id           TEXT NOT NULL REFERENCES friends (id) ON DELETE CASCADE,
  user_id             TEXT,
  affiliate_code      TEXT,
  metadata            TEXT,
  created_at          TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_conversion_events_point ON conversion_events (conversion_point_id);
CREATE INDEX IF NOT EXISTS idx_conversion_events_friend ON conversion_events (friend_id);
CREATE INDEX IF NOT EXISTS idx_conversion_events_affiliate ON conversion_events (affiliate_code);

-- ============================================================
-- Round 2: Affiliates
-- ============================================================
CREATE TABLE IF NOT EXISTS affiliates (
  id              TEXT PRIMARY KEY,
  name            TEXT NOT NULL,
  code            TEXT NOT NULL UNIQUE,
  commission_rate REAL NOT NULL DEFAULT 0,
  is_active       INTEGER NOT NULL DEFAULT 1,
  created_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

-- ============================================================
-- Round 2: Affiliate Clicks
-- ============================================================
CREATE TABLE IF NOT EXISTS affiliate_clicks (
  id           TEXT PRIMARY KEY,
  affiliate_id TEXT NOT NULL REFERENCES affiliates (id) ON DELETE CASCADE,
  url          TEXT,
  ip_address   TEXT,
  created_at   TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_affiliate_clicks_affiliate ON affiliate_clicks (affiliate_id);

-- ============================================================
-- Round 3: Webhook IN/OUT
-- ============================================================
CREATE TABLE IF NOT EXISTS incoming_webhooks (
  id          TEXT PRIMARY KEY,
  name        TEXT NOT NULL,
  source_type TEXT NOT NULL DEFAULT 'custom',
  secret      TEXT,
  is_active   INTEGER NOT NULL DEFAULT 1,
  created_at  TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at  TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE TABLE IF NOT EXISTS outgoing_webhooks (
  id          TEXT PRIMARY KEY,
  name        TEXT NOT NULL,
  url         TEXT NOT NULL,
  event_types TEXT NOT NULL DEFAULT '[]',
  secret      TEXT,
  is_active   INTEGER NOT NULL DEFAULT 1,
  created_at  TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at  TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

-- ============================================================
-- Round 3: Google Calendar
-- ============================================================
CREATE TABLE IF NOT EXISTS google_calendar_connections (
  id            TEXT PRIMARY KEY,
  calendar_id   TEXT NOT NULL,
  access_token  TEXT,
  refresh_token TEXT,
  api_key       TEXT,
  auth_type     TEXT NOT NULL DEFAULT 'api_key',
  is_active     INTEGER NOT NULL DEFAULT 1,
  created_at    TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at    TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE TABLE IF NOT EXISTS calendar_bookings (
  id             TEXT PRIMARY KEY,
  connection_id  TEXT NOT NULL REFERENCES google_calendar_connections (id) ON DELETE CASCADE,
  friend_id      TEXT REFERENCES friends (id) ON DELETE SET NULL,
  event_id       TEXT,
  title          TEXT NOT NULL,
  start_at       TEXT NOT NULL,
  end_at         TEXT NOT NULL,
  status         TEXT NOT NULL DEFAULT 'confirmed' CHECK (status IN ('confirmed', 'cancelled', 'completed')),
  metadata       TEXT,
  created_at     TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at     TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_calendar_bookings_friend ON calendar_bookings (friend_id);
CREATE INDEX IF NOT EXISTS idx_calendar_bookings_start ON calendar_bookings (start_at);

-- ============================================================
-- Round 3: リマインダ配信
-- ============================================================
CREATE TABLE IF NOT EXISTS reminders (
  id          TEXT PRIMARY KEY,
  name        TEXT NOT NULL,
  description TEXT,
  is_active   INTEGER NOT NULL DEFAULT 1,
  created_at  TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at  TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE TABLE IF NOT EXISTS reminder_steps (
  id              TEXT PRIMARY KEY,
  reminder_id     TEXT NOT NULL REFERENCES reminders (id) ON DELETE CASCADE,
  offset_minutes  INTEGER NOT NULL,
  message_type    TEXT NOT NULL CHECK (message_type IN ('text', 'image', 'flex')),
  message_content TEXT NOT NULL,
  created_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_reminder_steps_reminder ON reminder_steps (reminder_id);

CREATE TABLE IF NOT EXISTS friend_reminders (
  id              TEXT PRIMARY KEY,
  friend_id       TEXT NOT NULL REFERENCES friends (id) ON DELETE CASCADE,
  reminder_id     TEXT NOT NULL REFERENCES reminders (id) ON DELETE CASCADE,
  target_date     TEXT NOT NULL,
  status          TEXT NOT NULL DEFAULT 'active' CHECK (status IN ('active', 'completed', 'cancelled')),
  created_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_friend_reminders_status ON friend_reminders (status);
CREATE INDEX IF NOT EXISTS idx_friend_reminders_friend ON friend_reminders (friend_id);

CREATE TABLE IF NOT EXISTS friend_reminder_deliveries (
  id                TEXT PRIMARY KEY,
  friend_reminder_id TEXT NOT NULL REFERENCES friend_reminders (id) ON DELETE CASCADE,
  reminder_step_id  TEXT NOT NULL REFERENCES reminder_steps (id) ON DELETE CASCADE,
  delivered_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  UNIQUE (friend_reminder_id, reminder_step_id)
);

-- ============================================================
-- Round 3: スコアリング
-- ============================================================
CREATE TABLE IF NOT EXISTS scoring_rules (
  id          TEXT PRIMARY KEY,
  name        TEXT NOT NULL,
  event_type  TEXT NOT NULL,
  score_value INTEGER NOT NULL,
  is_active   INTEGER NOT NULL DEFAULT 1,
  created_at  TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at  TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE TABLE IF NOT EXISTS friend_scores (
  id              TEXT PRIMARY KEY,
  friend_id       TEXT NOT NULL REFERENCES friends (id) ON DELETE CASCADE,
  scoring_rule_id TEXT REFERENCES scoring_rules (id) ON DELETE SET NULL,
  score_change    INTEGER NOT NULL,
  reason          TEXT,
  created_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_friend_scores_friend ON friend_scores (friend_id);
CREATE INDEX IF NOT EXISTS idx_friend_scores_created ON friend_scores (created_at);

-- ============================================================
-- Round 3: テンプレート管理
-- ============================================================
CREATE TABLE IF NOT EXISTS templates (
  id              TEXT PRIMARY KEY,
  name            TEXT NOT NULL,
  category        TEXT NOT NULL DEFAULT 'general',
  message_type    TEXT NOT NULL CHECK (message_type IN ('text', 'image', 'flex', 'carousel')),
  message_content TEXT NOT NULL,
  created_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_templates_category ON templates (category);

-- ============================================================
-- Round 3: オペレーター/チャット
-- ============================================================
CREATE TABLE IF NOT EXISTS operators (
  id         TEXT PRIMARY KEY,
  name       TEXT NOT NULL,
  email      TEXT NOT NULL UNIQUE,
  role       TEXT NOT NULL DEFAULT 'operator' CHECK (role IN ('admin', 'operator')),
  is_active  INTEGER NOT NULL DEFAULT 1,
  created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE TABLE IF NOT EXISTS chats (
  id            TEXT PRIMARY KEY,
  friend_id     TEXT NOT NULL REFERENCES friends (id) ON DELETE CASCADE,
  operator_id   TEXT REFERENCES operators (id) ON DELETE SET NULL,
  status        TEXT NOT NULL DEFAULT 'unread' CHECK (status IN ('unread', 'in_progress', 'resolved')),
  notes         TEXT,
  last_message_at TEXT,
  created_at    TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at    TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_chats_friend ON chats (friend_id);
CREATE INDEX IF NOT EXISTS idx_chats_operator ON chats (operator_id);
CREATE INDEX IF NOT EXISTS idx_chats_status ON chats (status);

-- ============================================================
-- Round 3: 通知機能
-- ============================================================
CREATE TABLE IF NOT EXISTS notification_rules (
  id           TEXT PRIMARY KEY,
  name         TEXT NOT NULL,
  event_type   TEXT NOT NULL,
  conditions   TEXT NOT NULL DEFAULT '{}',
  channels     TEXT NOT NULL DEFAULT '["webhook"]',
  is_active    INTEGER NOT NULL DEFAULT 1,
  created_at   TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at   TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE TABLE IF NOT EXISTS notifications (
  id              TEXT PRIMARY KEY,
  rule_id         TEXT REFERENCES notification_rules (id) ON DELETE SET NULL,
  event_type      TEXT NOT NULL,
  title           TEXT NOT NULL,
  body            TEXT NOT NULL,
  channel         TEXT NOT NULL,
  status          TEXT NOT NULL DEFAULT 'pending' CHECK (status IN ('pending', 'sent', 'failed')),
  metadata        TEXT,
  created_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_notifications_status ON notifications (status);
CREATE INDEX IF NOT EXISTS idx_notifications_created ON notifications (created_at);

-- ============================================================
-- Round 3: Stripe決済連携
-- ============================================================
CREATE TABLE IF NOT EXISTS stripe_events (
  id               TEXT PRIMARY KEY,
  stripe_event_id  TEXT NOT NULL UNIQUE,
  event_type       TEXT NOT NULL,
  friend_id        TEXT REFERENCES friends (id) ON DELETE SET NULL,
  amount           REAL,
  currency         TEXT,
  metadata         TEXT,
  processed_at     TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_stripe_events_friend ON stripe_events (friend_id);
CREATE INDEX IF NOT EXISTS idx_stripe_events_type ON stripe_events (event_type);

-- ============================================================
-- Round 3: BAN検知 & リカバリ
-- ============================================================
CREATE TABLE IF NOT EXISTS account_health_logs (
  id              TEXT PRIMARY KEY,
  line_account_id TEXT NOT NULL,
  error_code      INTEGER,
  error_count     INTEGER NOT NULL DEFAULT 0,
  check_period    TEXT NOT NULL,
  risk_level      TEXT NOT NULL DEFAULT 'normal' CHECK (risk_level IN ('normal', 'warning', 'danger')),
  created_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_health_logs_account ON account_health_logs (line_account_id);

CREATE TABLE IF NOT EXISTS account_migrations (
  id               TEXT PRIMARY KEY,
  from_account_id  TEXT NOT NULL,
  to_account_id    TEXT NOT NULL,
  status           TEXT NOT NULL DEFAULT 'pending' CHECK (status IN ('pending', 'in_progress', 'completed', 'failed')),
  migrated_count   INTEGER NOT NULL DEFAULT 0,
  total_count      INTEGER NOT NULL DEFAULT 0,
  created_at       TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  completed_at     TEXT
);

-- ============================================================
-- Round 3: アクション自動化
-- ============================================================
CREATE TABLE IF NOT EXISTS automations (
  id          TEXT PRIMARY KEY,
  name        TEXT NOT NULL,
  description TEXT,
  event_type  TEXT NOT NULL,
  conditions  TEXT NOT NULL DEFAULT '{}',
  actions     TEXT NOT NULL DEFAULT '[]',
  is_active   INTEGER NOT NULL DEFAULT 1,
  priority    INTEGER NOT NULL DEFAULT 0,
  created_at  TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at  TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_automations_event ON automations (event_type);
CREATE INDEX IF NOT EXISTS idx_automations_active ON automations (is_active);

CREATE TABLE IF NOT EXISTS automation_logs (
  id             TEXT PRIMARY KEY,
  automation_id  TEXT NOT NULL REFERENCES automations (id) ON DELETE CASCADE,
  friend_id      TEXT REFERENCES friends (id) ON DELETE SET NULL,
  event_data     TEXT,
  actions_result TEXT,
  status         TEXT NOT NULL DEFAULT 'success' CHECK (status IN ('success', 'partial', 'failed')),
  created_at     TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_automation_logs_automation ON automation_logs (automation_id);

-- ============================================================
-- Ad Platform Configuration
-- ============================================================
CREATE TABLE IF NOT EXISTS ad_platforms (
  id           TEXT PRIMARY KEY,
  name         TEXT NOT NULL,
  display_name TEXT,
  config       TEXT NOT NULL DEFAULT '{}',
  is_active    INTEGER DEFAULT 1,
  created_at   TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at   TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

-- ============================================================
-- Ad Conversion Logs
-- ============================================================
CREATE TABLE IF NOT EXISTS ad_conversion_logs (
  id                  TEXT PRIMARY KEY,
  ad_platform_id      TEXT NOT NULL,
  friend_id           TEXT NOT NULL,
  conversion_point_id TEXT,
  event_name          TEXT NOT NULL,
  click_id            TEXT,
  click_id_type       TEXT,
  status              TEXT DEFAULT 'pending',
  request_body        TEXT,
  response_body       TEXT,
  error_message       TEXT,
  created_at          TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_ad_conversion_logs_platform ON ad_conversion_logs (ad_platform_id);
CREATE INDEX IF NOT EXISTS idx_ad_conversion_logs_friend ON ad_conversion_logs (friend_id);
CREATE INDEX IF NOT EXISTS idx_ad_conversion_logs_status ON ad_conversion_logs (status);

-- Staff member accounts with role-based access control
CREATE TABLE IF NOT EXISTS staff_members (
  id         TEXT PRIMARY KEY,
  name       TEXT NOT NULL,
  email      TEXT,
  role       TEXT NOT NULL CHECK (role IN ('owner', 'admin', 'staff')),
  api_key    TEXT UNIQUE NOT NULL,
  is_active  INTEGER NOT NULL DEFAULT 1,
  created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  -- ID/PASS ログイン (migration 076 / batch F)。既存行は NULL のまま = api_key ログイン維持。
  login_id            TEXT,
  password_hash       TEXT,
  password_salt       TEXT,
  password_algo       TEXT DEFAULT 'pbkdf2-sha256',
  password_iterations INTEGER,
  password_updated_at TEXT,
  failed_login_count  INTEGER DEFAULT 0,
  locked_until        TEXT,
  -- カスタムロール (migration 088 / G64)。NULL = built-in preset (role 列) で従来通り解決。
  role_id             TEXT
);

CREATE UNIQUE INDEX IF NOT EXISTS idx_staff_members_api_key ON staff_members(api_key);
CREATE INDEX IF NOT EXISTS idx_staff_members_role ON staff_members(role);
CREATE UNIQUE INDEX IF NOT EXISTS idx_staff_members_login_id
  ON staff_members(login_id) WHERE login_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_staff_members_role_id ON staff_members(role_id);

-- カスタムロール定義 (migration 086 / G64)。built-in owner/admin/staff はコード定数なので入らない。
CREATE TABLE IF NOT EXISTS roles (
  id          TEXT PRIMARY KEY,
  name        TEXT NOT NULL,
  description TEXT,
  base_role   TEXT NOT NULL DEFAULT 'staff',
  is_builtin  INTEGER NOT NULL DEFAULT 0,
  created_at  TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at  TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

-- custom role の機能単位権限 (migration 087 / G64)。allowed=1 の feature のみ許可 (厳格 allowlist)。
CREATE TABLE IF NOT EXISTS role_permissions (
  id          TEXT PRIMARY KEY,
  role_id     TEXT NOT NULL,
  feature_key TEXT NOT NULL,
  allowed     INTEGER NOT NULL DEFAULT 0,
  created_at  TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);
CREATE UNIQUE INDEX IF NOT EXISTS idx_role_permissions_role_feature
  ON role_permissions(role_id, feature_key);

-- Reusable message templates (text or Flex) for reward messages in campaigns
CREATE TABLE IF NOT EXISTS message_templates (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  message_type TEXT NOT NULL CHECK (message_type IN ('text', 'flex')),
  message_content TEXT NOT NULL,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);

-- Pool accounts — multiple LINE accounts per traffic pool for distribution
CREATE TABLE IF NOT EXISTS pool_accounts (
  id TEXT PRIMARY KEY,
  pool_id TEXT NOT NULL REFERENCES traffic_pools(id) ON DELETE CASCADE,
  line_account_id TEXT NOT NULL REFERENCES line_accounts(id) ON DELETE CASCADE,
  is_active INTEGER NOT NULL DEFAULT 1,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  UNIQUE(pool_id, line_account_id)
);
-- Migration 036: Booking feature (Phase 1)
-- See: docs/superpowers/specs/2026-05-08-booking-design.md
--
-- Conventions follow schema.sql: TEXT (UUID/nanoid) primary keys,
-- created_at default in JST. Time-of-event columns (starts_at / ends_at /
-- block_ends_at / requested_at / scheduled_at / sent_at / decided_at /
-- expires_at) are written by the Worker as UTC ISO8601 (Z-suffixed) and
-- have NO default — callers must provide them.

-- ============================================================
-- menus: メニューマスタ
-- ============================================================
CREATE TABLE IF NOT EXISTS menus (
  id                    TEXT PRIMARY KEY,
  line_account_id       TEXT NOT NULL,
  name                  TEXT NOT NULL,
  category_label        TEXT,
  description           TEXT,
  duration_minutes      INTEGER NOT NULL,
  buffer_after_minutes  INTEGER NOT NULL DEFAULT 0,
  base_price            INTEGER NOT NULL,
  sort_order            INTEGER NOT NULL DEFAULT 0,
  is_active             INTEGER NOT NULL DEFAULT 1,
  deleted_at            TEXT,
  created_at            TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at            TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  FOREIGN KEY (line_account_id) REFERENCES line_accounts(id)
);
CREATE INDEX IF NOT EXISTS idx_menus_account_sort ON menus (line_account_id, sort_order);

-- ============================================================
-- staff: スタッフ
-- ============================================================
CREATE TABLE IF NOT EXISTS staff (
  id                       TEXT PRIMARY KEY,
  line_account_id          TEXT NOT NULL,
  name                     TEXT NOT NULL,
  display_name             TEXT NOT NULL,
  role                     TEXT,
  profile_image_url        TEXT,
  bio                      TEXT,
  sort_order               INTEGER NOT NULL DEFAULT 0,
  is_designation_optional  INTEGER NOT NULL DEFAULT 0,
  is_active                INTEGER NOT NULL DEFAULT 1,
  deleted_at               TEXT,
  created_at               TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at               TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  FOREIGN KEY (line_account_id) REFERENCES line_accounts(id)
);
CREATE INDEX IF NOT EXISTS idx_staff_account_sort ON staff (line_account_id, sort_order);

-- ============================================================
-- staff_menus: スタッフ x メニュー (提供可否・上書き値)
-- ============================================================
CREATE TABLE IF NOT EXISTS staff_menus (
  staff_id                  TEXT NOT NULL,
  menu_id                   TEXT NOT NULL,
  is_offered                INTEGER NOT NULL DEFAULT 1,
  override_duration_minutes INTEGER,
  override_price            INTEGER,
  PRIMARY KEY (staff_id, menu_id),
  FOREIGN KEY (staff_id) REFERENCES staff(id),
  FOREIGN KEY (menu_id) REFERENCES menus(id)
);

-- ============================================================
-- staff_shifts: シフト (レコードなし = その日休み)
-- ============================================================
CREATE TABLE IF NOT EXISTS staff_shifts (
  id          TEXT PRIMARY KEY,
  staff_id    TEXT NOT NULL,
  work_date   TEXT NOT NULL,    -- YYYY-MM-DD (JST)
  start_time  TEXT NOT NULL,    -- HH:MM (JST)
  end_time    TEXT NOT NULL,    -- HH:MM (JST)
  created_at  TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at  TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  UNIQUE (staff_id, work_date),
  FOREIGN KEY (staff_id) REFERENCES staff(id)
);
CREATE INDEX IF NOT EXISTS idx_shifts_staff_date ON staff_shifts (staff_id, work_date);

-- ============================================================
-- bookings: 予約本体
-- ============================================================
CREATE TABLE IF NOT EXISTS bookings (
  id                      TEXT PRIMARY KEY,
  line_account_id         TEXT NOT NULL,
  friend_id               TEXT NOT NULL,        -- friends.id
  staff_id                TEXT NOT NULL,
  menu_id                 TEXT NOT NULL,
  starts_at               TEXT NOT NULL,        -- UTC ISO8601 (Z)
  ends_at                 TEXT NOT NULL,        -- UTC ISO8601 (Z)
  block_ends_at           TEXT NOT NULL,        -- ends_at + buffer_after。衝突判定
  status                  TEXT NOT NULL CHECK (status IN ('requested','confirmed','rejected','expired','cancelled','completed','no_show')),
  customer_note           TEXT,
  internal_note           TEXT,
  price_at_booking        INTEGER NOT NULL,
  requested_at            TEXT NOT NULL,        -- UTC ISO8601
  decided_at              TEXT,                 -- UTC ISO8601
  decided_by_staff_id     TEXT,
  external_event_id       TEXT,                 -- Phase 3 余地 (Google Calendar)
  external_calendar_id    TEXT,                 -- Phase 3 余地
  created_at              TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at              TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  FOREIGN KEY (line_account_id) REFERENCES line_accounts(id),
  FOREIGN KEY (friend_id) REFERENCES friends(id),
  FOREIGN KEY (staff_id) REFERENCES staff(id),
  FOREIGN KEY (menu_id) REFERENCES menus(id)
);
CREATE INDEX IF NOT EXISTS idx_bookings_account_status_starts ON bookings (line_account_id, status, starts_at);
CREATE INDEX IF NOT EXISTS idx_bookings_staff_overlap ON bookings (staff_id, status, starts_at, block_ends_at);
CREATE INDEX IF NOT EXISTS idx_bookings_friend_starts ON bookings (friend_id, starts_at DESC);

-- ============================================================
-- booking_idempotency_keys: LIFF 多重送信防止
-- ============================================================
CREATE TABLE IF NOT EXISTS booking_idempotency_keys (
  key              TEXT PRIMARY KEY,
  line_account_id  TEXT NOT NULL,
  friend_id        TEXT NOT NULL,
  response_status  INTEGER NOT NULL,
  response_body    TEXT NOT NULL,
  created_at       TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  expires_at       TEXT NOT NULL                  -- UTC ISO8601
);
CREATE INDEX IF NOT EXISTS idx_idempotency_expires ON booking_idempotency_keys (expires_at);

-- ============================================================
-- booking_reminders: 前日 / 当日 N 時間前リマインダ
-- ============================================================
CREATE TABLE IF NOT EXISTS booking_reminders (
  id            TEXT PRIMARY KEY,
  booking_id    TEXT NOT NULL,
  kind          TEXT NOT NULL CHECK (kind IN ('day_before','hours_before')),
  scheduled_at  TEXT NOT NULL,                                -- UTC ISO8601
  sent_at       TEXT,                                         -- UTC ISO8601
  status        TEXT NOT NULL DEFAULT 'pending' CHECK (status IN ('pending','sent','failed','failed_permanent','cancelled')),
  retry_count   INTEGER NOT NULL DEFAULT 0,
  last_error    TEXT,
  FOREIGN KEY (booking_id) REFERENCES bookings(id)
);
CREATE INDEX IF NOT EXISTS idx_reminders_status_scheduled ON booking_reminders (status, scheduled_at);


-- =============================================================================
-- Rich Menu Editor (migration 035) — groups / pages / areas
-- =============================================================================
CREATE TABLE IF NOT EXISTS rich_menu_groups (
  id                 TEXT PRIMARY KEY,
  account_id         TEXT NOT NULL REFERENCES line_accounts(id) ON DELETE CASCADE,
  name               TEXT NOT NULL,
  chat_bar_text      TEXT NOT NULL,
  size               TEXT NOT NULL CHECK (size IN ('large','compact')),
  default_page_id    TEXT,
  is_default_for_all INTEGER NOT NULL DEFAULT 0,
  status             TEXT NOT NULL DEFAULT 'draft' CHECK (status IN ('draft','published')),
  publishing_at      TEXT,
  -- schedule_start / schedule_end (migration 058 / F2 batch4 G17): 期間限定メニューの開始/終了
  -- (ISO8601 JST・NULL = スケジュールなし)。自動切替は RICH_MENU_SCHEDULE_ENABLED flag OFF + crons=[]
  -- で dark-ship (発火しない)。
  schedule_start     TEXT,
  schedule_end       TEXT,
  created_at         TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at         TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE TABLE IF NOT EXISTS rich_menu_pages (
  id                 TEXT PRIMARY KEY,
  group_id           TEXT NOT NULL REFERENCES rich_menu_groups(id) ON DELETE CASCADE,
  order_index        INTEGER NOT NULL,
  name               TEXT NOT NULL,
  alias_id           TEXT NOT NULL,
  line_richmenu_id   TEXT,
  image_r2_key       TEXT,
  image_content_type TEXT,
  created_at         TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at         TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  UNIQUE (group_id, order_index)
);

CREATE TABLE IF NOT EXISTS rich_menu_areas (
  id              TEXT PRIMARY KEY,
  page_id         TEXT NOT NULL REFERENCES rich_menu_pages(id) ON DELETE CASCADE,
  bounds_x        INTEGER NOT NULL,
  bounds_y        INTEGER NOT NULL,
  bounds_width    INTEGER NOT NULL,
  bounds_height   INTEGER NOT NULL,
  action_type     TEXT NOT NULL CHECK (action_type IN ('uri','message','postback','richmenuswitch')),
  action_data     TEXT NOT NULL,
  created_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE INDEX IF NOT EXISTS idx_rich_menu_pages_group    ON rich_menu_pages(group_id, order_index);
CREATE INDEX IF NOT EXISTS idx_rich_menu_areas_page     ON rich_menu_areas(page_id);
CREATE INDEX IF NOT EXISTS idx_rich_menu_groups_account ON rich_menu_groups(account_id, status);


-- =============================================================================
-- Conditional rich-menu display rules (migration 107)
-- =============================================================================
CREATE TABLE IF NOT EXISTS rich_menu_display_rules (
  id              TEXT PRIMARY KEY,
  account_id      TEXT NOT NULL REFERENCES line_accounts(id) ON DELETE CASCADE,
  name            TEXT NOT NULL CHECK (length(name) BETWEEN 1 AND 80),
  condition_type  TEXT NOT NULL CHECK (condition_type IN ('tag_exists', 'tag_not_exists', 'metadata_equals', 'metadata_not_equals', 'metadata_contains', 'metadata_not_contains', 'tag_name_contains', 'tag_name_not_contains')),
  condition_value TEXT NOT NULL CHECK (length(condition_value) BETWEEN 1 AND 10000),
  rich_menu_id    TEXT NOT NULL CHECK (length(rich_menu_id) BETWEEN 1 AND 200),
  priority        INTEGER NOT NULL DEFAULT 0 CHECK (priority BETWEEN -1000000 AND 1000000),
  is_active       INTEGER NOT NULL DEFAULT 1 CHECK (is_active IN (0, 1)),
  active_from     TEXT,
  active_until    TEXT,
  created_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE TABLE IF NOT EXISTS rich_menu_friend_assignments (
  friend_id    TEXT PRIMARY KEY REFERENCES friends(id) ON DELETE CASCADE,
  account_id   TEXT NOT NULL REFERENCES line_accounts(id) ON DELETE CASCADE,
  rule_id      TEXT REFERENCES rich_menu_display_rules(id) ON DELETE SET NULL,
  rich_menu_id TEXT,
  applied_at   TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at   TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE TABLE IF NOT EXISTS rich_menu_rule_evaluation_queue (
  friend_id    TEXT PRIMARY KEY REFERENCES friends(id) ON DELETE CASCADE,
  attempts     INTEGER NOT NULL DEFAULT 0 CHECK (attempts >= 0),
  available_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  last_error   TEXT,
  lease_token  TEXT,
  revision     INTEGER NOT NULL DEFAULT 1 CHECK (revision >= 1),
  created_at   TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at   TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE TABLE IF NOT EXISTS rich_menu_rule_reapply_jobs (
  id              TEXT PRIMARY KEY,
  account_id      TEXT NOT NULL REFERENCES line_accounts(id) ON DELETE CASCADE,
  status          TEXT NOT NULL DEFAULT 'running' CHECK (status IN ('running', 'completed')),
  total_count     INTEGER NOT NULL DEFAULT 0 CHECK (total_count >= 0),
  processed_count INTEGER NOT NULL DEFAULT 0 CHECK (processed_count >= 0),
  applied_count   INTEGER NOT NULL DEFAULT 0 CHECK (applied_count >= 0),
  skipped_count   INTEGER NOT NULL DEFAULT 0 CHECK (skipped_count >= 0),
  failed_count    INTEGER NOT NULL DEFAULT 0 CHECK (failed_count >= 0),
  last_friend_id  TEXT,
  locked_until    TEXT,
  lock_token      TEXT,
  created_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  completed_at    TEXT
);

CREATE TABLE IF NOT EXISTS rich_menu_rule_schedule_state (
  id              INTEGER PRIMARY KEY CHECK (id = 1),
  last_scanned_at TEXT NOT NULL
);

CREATE INDEX IF NOT EXISTS idx_rich_menu_display_rules_winner
  ON rich_menu_display_rules(account_id, is_active, priority DESC, created_at ASC, id ASC);
CREATE INDEX IF NOT EXISTS idx_rich_menu_friend_assignments_account
  ON rich_menu_friend_assignments(account_id, friend_id);
CREATE INDEX IF NOT EXISTS idx_rich_menu_rule_queue_ready
  ON rich_menu_rule_evaluation_queue(available_at, friend_id);
CREATE INDEX IF NOT EXISTS idx_rich_menu_rule_reapply_jobs_latest
  ON rich_menu_rule_reapply_jobs(account_id, created_at DESC);
CREATE UNIQUE INDEX IF NOT EXISTS idx_rich_menu_rule_reapply_jobs_one_running
  ON rich_menu_rule_reapply_jobs(account_id) WHERE status = 'running';
CREATE INDEX IF NOT EXISTS idx_rich_menu_rule_schedule_from
  ON rich_menu_display_rules(is_active, active_from, account_id) WHERE active_from IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_rich_menu_rule_schedule_until
  ON rich_menu_display_rules(is_active, active_until, account_id) WHERE active_until IS NOT NULL;

CREATE TRIGGER IF NOT EXISTS trg_rich_menu_rule_tag_insert AFTER INSERT ON friend_tags BEGIN INSERT INTO rich_menu_rule_evaluation_queue (friend_id, attempts, available_at, last_error, lease_token, revision, updated_at) SELECT NEW.friend_id, 0, strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'), NULL, NULL, 1, strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours') WHERE EXISTS (SELECT 1 FROM friends f JOIN rich_menu_display_rules r ON r.account_id = f.line_account_id AND r.is_active = 1 WHERE f.id = NEW.friend_id) OR EXISTS (SELECT 1 FROM rich_menu_friend_assignments a WHERE a.friend_id = NEW.friend_id) ON CONFLICT(friend_id) DO UPDATE SET attempts = 0, available_at = CASE WHEN rich_menu_rule_evaluation_queue.lease_token IS NULL THEN excluded.available_at ELSE rich_menu_rule_evaluation_queue.available_at END, last_error = NULL, revision = rich_menu_rule_evaluation_queue.revision + 1, updated_at = excluded.updated_at; END;
CREATE TRIGGER IF NOT EXISTS trg_rich_menu_rule_tag_delete AFTER DELETE ON friend_tags BEGIN INSERT INTO rich_menu_rule_evaluation_queue (friend_id, attempts, available_at, last_error, lease_token, revision, updated_at) SELECT OLD.friend_id, 0, strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'), NULL, NULL, 1, strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours') WHERE EXISTS (SELECT 1 FROM friends WHERE id = OLD.friend_id) AND (EXISTS (SELECT 1 FROM friends f JOIN rich_menu_display_rules r ON r.account_id = f.line_account_id AND r.is_active = 1 WHERE f.id = OLD.friend_id) OR EXISTS (SELECT 1 FROM rich_menu_friend_assignments a WHERE a.friend_id = OLD.friend_id)) ON CONFLICT(friend_id) DO UPDATE SET attempts = 0, available_at = CASE WHEN rich_menu_rule_evaluation_queue.lease_token IS NULL THEN excluded.available_at ELSE rich_menu_rule_evaluation_queue.available_at END, last_error = NULL, revision = rich_menu_rule_evaluation_queue.revision + 1, updated_at = excluded.updated_at; END;
CREATE TRIGGER IF NOT EXISTS trg_rich_menu_rule_tag_name_update AFTER UPDATE OF name ON tags WHEN OLD.name IS NOT NEW.name BEGIN INSERT INTO rich_menu_rule_evaluation_queue (friend_id, attempts, available_at, last_error, lease_token, revision, updated_at) SELECT ft.friend_id, 0, strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'), NULL, NULL, 1, strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours') FROM friend_tags ft JOIN friends f ON f.id = ft.friend_id WHERE ft.tag_id = NEW.id AND (EXISTS (SELECT 1 FROM rich_menu_display_rules r WHERE r.account_id = f.line_account_id AND r.is_active = 1) OR EXISTS (SELECT 1 FROM rich_menu_friend_assignments a WHERE a.friend_id = ft.friend_id)) ON CONFLICT(friend_id) DO UPDATE SET attempts = 0, available_at = CASE WHEN rich_menu_rule_evaluation_queue.lease_token IS NULL THEN excluded.available_at ELSE rich_menu_rule_evaluation_queue.available_at END, last_error = NULL, revision = rich_menu_rule_evaluation_queue.revision + 1, updated_at = excluded.updated_at; END;
CREATE TRIGGER IF NOT EXISTS trg_rich_menu_rule_friend_update AFTER UPDATE OF metadata, line_account_id, is_following ON friends WHEN OLD.metadata IS NOT NEW.metadata OR OLD.line_account_id IS NOT NEW.line_account_id OR (OLD.is_following IS NOT 1 AND NEW.is_following = 1) BEGIN INSERT INTO rich_menu_rule_evaluation_queue (friend_id, attempts, available_at, last_error, lease_token, revision, updated_at) SELECT NEW.id, 0, strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'), NULL, NULL, 1, strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours') WHERE EXISTS (SELECT 1 FROM rich_menu_display_rules r WHERE r.account_id = NEW.line_account_id AND r.is_active = 1) OR EXISTS (SELECT 1 FROM rich_menu_friend_assignments a WHERE a.friend_id = NEW.id) ON CONFLICT(friend_id) DO UPDATE SET attempts = 0, available_at = CASE WHEN rich_menu_rule_evaluation_queue.lease_token IS NULL THEN excluded.available_at ELSE rich_menu_rule_evaluation_queue.available_at END, last_error = NULL, revision = rich_menu_rule_evaluation_queue.revision + 1, updated_at = excluded.updated_at; END;
CREATE TRIGGER IF NOT EXISTS trg_rich_menu_rule_account_reactivate AFTER UPDATE OF is_active ON line_accounts WHEN OLD.is_active IS NOT 1 AND NEW.is_active = 1 BEGIN INSERT INTO rich_menu_rule_evaluation_queue (friend_id, attempts, available_at, last_error, lease_token, revision, updated_at) SELECT f.id, 0, strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'), NULL, NULL, 1, strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours') FROM friends f WHERE f.line_account_id = NEW.id AND f.is_following = 1 AND (EXISTS (SELECT 1 FROM rich_menu_display_rules r WHERE r.account_id = NEW.id AND r.is_active = 1) OR EXISTS (SELECT 1 FROM rich_menu_friend_assignments a WHERE a.friend_id = f.id)) ON CONFLICT(friend_id) DO UPDATE SET attempts = 0, available_at = CASE WHEN rich_menu_rule_evaluation_queue.lease_token IS NULL THEN excluded.available_at ELSE rich_menu_rule_evaluation_queue.available_at END, last_error = NULL, revision = rich_menu_rule_evaluation_queue.revision + 1, updated_at = excluded.updated_at; END;


-- =============================================================================
-- Response Schedules (migration 048 / G28) — 応答時間帯スケジュール
-- 営業時間内=オペレーター対応 / 時間外=自動応答 or 不在メッセージ。
-- is_enabled 既定 0 (OFF) = 既存 auto-reply 挙動の非回帰。
-- weekly_hours JSON: [{day:0..6 (0=日曜/getUTCDay準拠), closed:bool, open:'HH:MM', close:'HH:MM'}]
-- =============================================================================
CREATE TABLE IF NOT EXISTS response_schedules (
  id                 TEXT PRIMARY KEY,
  line_account_id    TEXT DEFAULT NULL,
  is_enabled         INTEGER NOT NULL DEFAULT 0,
  timezone           TEXT NOT NULL DEFAULT 'Asia/Tokyo'
                     CHECK (timezone = 'Asia/Tokyo'),
  outside_hours_mode TEXT NOT NULL DEFAULT 'auto_reply'
                     CHECK (outside_hours_mode IN ('auto_reply','away_message','none')),
  away_message       TEXT DEFAULT NULL,
  weekly_hours       TEXT NOT NULL DEFAULT '[]',
  created_at         TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at         TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);
CREATE INDEX IF NOT EXISTS idx_response_schedules_account ON response_schedules(line_account_id);


-- =============================================================================
-- Saved Searches (migration 049 / G10) — 保存済み検索 (セグメント)
-- 友だち絞込条件を名前付きで保存・再利用。conditions は broadcast が消費する
-- SegmentCondition JSON ({operator, rules[]}) と同一形式 (配信対象への流用余地)。
-- =============================================================================
CREATE TABLE IF NOT EXISTS saved_searches (
  id               TEXT PRIMARY KEY,
  line_account_id  TEXT DEFAULT NULL,
  name             TEXT NOT NULL,
  conditions       TEXT NOT NULL DEFAULT '{"operator":"AND","rules":[]}',
  created_at       TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at       TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);
CREATE INDEX IF NOT EXISTS idx_saved_searches_account ON saved_searches(line_account_id);


-- =============================================================================
-- Canned Responses (migration 050 / G23) — チャット定型文
-- 個別 1:1 チャットの返信に差し込む定型文 (title + content)。message_templates
-- (配信テンプレ) とは別責務。挿入 UI は本文を入力欄に貼るだけで送信経路には
-- 触れない。line_account_id が NULL なら全アカ共通、それ以外は account スコープ。
-- =============================================================================
CREATE TABLE IF NOT EXISTS canned_responses (
  id               TEXT PRIMARY KEY,
  line_account_id  TEXT DEFAULT NULL,
  title            TEXT NOT NULL,
  content          TEXT NOT NULL,
  created_at       TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at       TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);
CREATE INDEX IF NOT EXISTS idx_canned_responses_account ON canned_responses(line_account_id);


-- =============================================================================
-- Campaigns (migration 051 / F2 G3) — キャンペーン集計
-- 複数の配信 (broadcasts.campaign_id で紐付け) を1キャンペーンとして束ね、まとめて
-- 成果を見る。account_id NOT NULL = account-scoped (別アカウントの成果は見えない)。
-- 送信には関与しない (集計・紐付けのみ)。
-- =============================================================================
CREATE TABLE IF NOT EXISTS campaigns (
  id               TEXT PRIMARY KEY,
  account_id       TEXT NOT NULL REFERENCES line_accounts(id) ON DELETE CASCADE,
  name             TEXT NOT NULL,
  created_at       TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at       TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);
CREATE INDEX IF NOT EXISTS idx_campaigns_account ON campaigns(account_id);


-- =============================================================================
-- Template Packs (migration 053 / F2 G16) — テンプレパック (複数吹き出しセット)
-- 「あいさつ→案内→CTA」のような複数吹き出しを1パックとして保存し、配信作成時に
-- まとめて挿入する。account_id NOT NULL = account-scoped (別アカウントのパック文面は
-- list/選択に出ない)。既存 message_templates (単発テンプレ) とは別責務・別表。
-- 挿入 UI は broadcast-form の state に載せるだけで送信経路には触れない。
-- =============================================================================
CREATE TABLE IF NOT EXISTS template_packs (
  id               TEXT PRIMARY KEY,
  account_id       TEXT NOT NULL REFERENCES line_accounts(id) ON DELETE CASCADE,
  name             TEXT NOT NULL,
  created_at       TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at       TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);
CREATE INDEX IF NOT EXISTS idx_template_packs_account ON template_packs(account_id);

CREATE TABLE IF NOT EXISTS template_pack_items (
  id               TEXT PRIMARY KEY,
  pack_id          TEXT NOT NULL REFERENCES template_packs(id) ON DELETE CASCADE,
  order_index      INTEGER NOT NULL,
  message_type     TEXT NOT NULL CHECK (message_type IN ('text', 'flex', 'image', 'video', 'audio', 'sticker', 'imagemap', 'richvideo')),
  message_content  TEXT NOT NULL,
  created_at       TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at       TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);
CREATE INDEX IF NOT EXISTS idx_template_pack_items_pack ON template_pack_items(pack_id, order_index);

-- =============================================================================
-- Sender presets (migration 055 / F2 G25 送信者名・アイコン切替)
-- account-scoped。broadcasts は sender_preset_id で id 参照するのみ (生 name/iconUrl は持たない)。
-- =============================================================================
CREATE TABLE IF NOT EXISTS sender_presets (
  id              TEXT PRIMARY KEY,
  line_account_id TEXT NOT NULL REFERENCES line_accounts (id) ON DELETE CASCADE,
  name            TEXT NOT NULL,
  icon_url        TEXT,
  created_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);
CREATE INDEX IF NOT EXISTS idx_sender_presets_account ON sender_presets (line_account_id);

-- =============================================================================
-- A/B tests (migration 056 / F2 batch4 G1 A/B テスト配信)
-- account-scoped。broadcasts.ab_test_id / ab_variant で案 A/B の配信を紐付ける。
-- 分割・比較・勝ち選定は application 層 (services/ab-split.ts)。実 A/B 送信は owner 立会 gated。
-- =============================================================================
CREATE TABLE IF NOT EXISTS ab_tests (
  id                  TEXT PRIMARY KEY,
  account_id          TEXT NOT NULL REFERENCES line_accounts (id) ON DELETE CASCADE,
  name                TEXT NOT NULL,
  metric              TEXT NOT NULL CHECK (metric IN ('open_rate', 'click_rate')),
  status              TEXT NOT NULL DEFAULT 'draft' CHECK (status IN ('draft', 'running', 'decided')),
  winner_broadcast_id TEXT REFERENCES broadcasts (id) ON DELETE SET NULL,
  created_at          TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at          TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);
CREATE INDEX IF NOT EXISTS idx_ab_tests_account ON ab_tests (account_id);

-- =============================================================================
-- Formaloo ミラー基盤 (migration 079 / F-1 / line-formaloo-forms)。§4 SoT: Formaloo =
-- 定義/レンダリングの正本、D1 = マッピング台帳 + 回答ミラー + 同期状態の正本。native forms は無改変併存。
-- =============================================================================
CREATE TABLE IF NOT EXISTS formaloo_forms (
  id                    TEXT PRIMARY KEY,
  formaloo_slug         TEXT,
  title                 TEXT NOT NULL DEFAULT '',
  description           TEXT,
  definition_json       TEXT NOT NULL DEFAULT '{}',
  on_submit_tag_id      TEXT REFERENCES tags (id) ON DELETE SET NULL,
  on_submit_scenario_id TEXT REFERENCES scenarios (id) ON DELETE SET NULL,
  submit_message        TEXT,
  submit_count          INTEGER NOT NULL DEFAULT 0,
  deleted               INTEGER NOT NULL DEFAULT 0,
  builder_status        TEXT NOT NULL DEFAULT 'draft',   -- migration 080: draft|in_review|published (publish gate / N-7)
  published_at          TEXT,                            -- migration 080: 初回公開時刻 (NULL=未公開)
  gsheet_connected      INTEGER NOT NULL DEFAULT 0,      -- migration 083: Google Sheets 連携済 (T-E1)
  gsheet_url            TEXT,                            -- migration 083: 連携先 Sheet URL (表示用 / NULL=未連携)
  line_account_id       TEXT,                            -- migration 095: 表示スコープ (NULL=全アカウント共通 / F6-2 本柱②)
  workspace_id          TEXT,                            -- migration 095: 作成先 Formaloo workspace (NULL=env 鍵 fallback / F6-2 本柱④)
  folder_id             TEXT,                            -- migration 096: ハーネス側フォルダ分類 (NULL=未分類 / F6-3 本柱③)
  friend_metadata_mappings_json TEXT NOT NULL DEFAULT '[]', -- migration 103: Formaloo row → friend.metadata (空配列=OFF)
  render_backend        TEXT NOT NULL DEFAULT 'formaloo' -- migration 113: formaloo|internal (既存は Formaloo 維持)
                        CHECK (render_backend IN ('formaloo', 'internal')),
  created_at            TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at            TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);
CREATE INDEX IF NOT EXISTS idx_formaloo_forms_slug ON formaloo_forms (formaloo_slug);
CREATE INDEX IF NOT EXISTS idx_formaloo_forms_account ON formaloo_forms (line_account_id, deleted, updated_at);
CREATE INDEX IF NOT EXISTS idx_formaloo_forms_folder ON formaloo_forms (folder_id);

-- migration 108: choice_fetch の公開 GET が読む、form 単位の Harness 管理選択肢リスト。
-- item は Formaloo 公式契約の {label,value}[] を items_json に保持し、公開 route が最大10件へ絞る。
CREATE TABLE IF NOT EXISTS formaloo_choice_lists (
  id         TEXT PRIMARY KEY,
  form_id    TEXT NOT NULL,
  name       TEXT NOT NULL,
  items_json TEXT NOT NULL DEFAULT '[]',
  created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);
CREATE INDEX IF NOT EXISTS idx_formaloo_choice_lists_form ON formaloo_choice_lists (form_id, updated_at);

-- migration 096: ハーネス側フォルダ分類 (SoT / F6-3 本柱③)。Formaloo 側フォルダとは自動連動しない (API 非露出 / N-19)。
-- line_account_id は NOT NULL (フォルダは必ず account に属す / Codex M#3)。FK off = アプリ層で cross-account/循環/削除を解決。
CREATE TABLE IF NOT EXISTS formaloo_folders (
  id              TEXT PRIMARY KEY,
  line_account_id TEXT NOT NULL,
  name            TEXT NOT NULL,
  parent_id       TEXT,
  position        INTEGER NOT NULL DEFAULT 0,
  created_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at      TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);
CREATE INDEX IF NOT EXISTS idx_formaloo_folders_account ON formaloo_folders (line_account_id);

-- migration 095: 作成時の既定 workspace 解決台帳 (F6-2)。line_account_id PK → default_workspace_id。
-- 平文鍵は持たない (D-2)。無効/未登録 workspace を指す binding は resolver の active 判定で NULL に落とす。
CREATE TABLE IF NOT EXISTS formaloo_account_bindings (
  line_account_id      TEXT PRIMARY KEY,
  default_workspace_id TEXT,
  created_at           TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at           TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE TABLE IF NOT EXISTS formaloo_submissions (
  id            TEXT PRIMARY KEY,
  form_id       TEXT NOT NULL,
  formaloo_slug TEXT,
  friend_id     TEXT,
  answers_json  TEXT NOT NULL DEFAULT '{}',
  submitted_at  TEXT NOT NULL,
  synced_at     TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  line_processed INTEGER NOT NULL DEFAULT 0,   -- migration 081: LINE 後処理発火済 claim (再送二重発火防止 / N-3)
  verified       INTEGER NOT NULL DEFAULT 0    -- migration 081: 署名 or pull-verify 済 (未署名隔離 / N-12)
);
CREATE INDEX IF NOT EXISTS idx_formaloo_submissions_form ON formaloo_submissions (form_id, submitted_at);
CREATE INDEX IF NOT EXISTS idx_formaloo_submissions_friend ON formaloo_submissions (friend_id);
CREATE INDEX IF NOT EXISTS idx_formaloo_submissions_unverified ON formaloo_submissions (form_id, verified);

-- migration 113: 自前配信の回答。Formaloo 回答ミラーとは別 table にして並行運用を保つ。
CREATE TABLE IF NOT EXISTS internal_form_submissions (
  id           TEXT PRIMARY KEY,
  form_id      TEXT NOT NULL,
  friend_id    TEXT,
  answers_json TEXT NOT NULL DEFAULT '{}',
  origin_channel TEXT NOT NULL DEFAULT 'embed'
                 CHECK (origin_channel IN ('line', 'embed', 'invalid')),
  edit_version INTEGER NOT NULL DEFAULT 0 CHECK (edit_version >= 0),
  deleted_at   TEXT,
  submitted_at TEXT NOT NULL,
  created_at   TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);
CREATE INDEX IF NOT EXISTS idx_internal_form_submissions_form
  ON internal_form_submissions (form_id, submitted_at);
CREATE INDEX IF NOT EXISTS idx_internal_form_submissions_friend
  ON internal_form_submissions (friend_id);

-- migration 124: 回答者本人向け通知設定と internal 編集リンクの失効世代。
CREATE TABLE IF NOT EXISTS internal_form_notification_settings (
  form_id                  TEXT PRIMARY KEY REFERENCES formaloo_forms (id) ON DELETE CASCADE,
  enabled                  INTEGER NOT NULL DEFAULT 0 CHECK (enabled IN (0, 1)),
  recipient_email_field_id TEXT,
  message_template         TEXT,
  edit_link_epoch          INTEGER NOT NULL DEFAULT 0 CHECK (edit_link_epoch >= 0),
  created_at               TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at               TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);

CREATE TABLE IF NOT EXISTS formaloo_field_map (
  id                  TEXT PRIMARY KEY,
  form_id             TEXT NOT NULL,
  formaloo_field_slug TEXT,
  field_type          TEXT NOT NULL,
  label               TEXT NOT NULL DEFAULT '',
  position            INTEGER NOT NULL DEFAULT 0,
  config_json         TEXT NOT NULL DEFAULT '{}',
  created_at          TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at          TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);
CREATE INDEX IF NOT EXISTS idx_formaloo_field_map_form ON formaloo_field_map (form_id, position);

CREATE TABLE IF NOT EXISTS formaloo_sync_state (
  form_id        TEXT PRIMARY KEY,
  last_pushed_at TEXT,
  last_pulled_at TEXT,
  sync_status    TEXT NOT NULL DEFAULT 'idle',
  last_error     TEXT,
  updated_at     TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  -- migration 098 (formaloo-auto-pull): drift 検知の別軸 (sync_status と直交)。
  remote_definition_hash TEXT,                          -- baseline fingerprint (NULL=未 bootstrap)
  pending_remote_hash    TEXT,                          -- 通知中 drift の fingerprint (dedup キー)
  drift_status           TEXT NOT NULL DEFAULT 'none',  -- none|detected|applied|conflict
  drift_detected_at      TEXT,                          -- 最新 drift 検知時刻 (JST ISO)
  remote_updated_at      TEXT                           -- optional: list timestamp フィルタ用 (live 実在時)
);

-- 定義 drift の監査履歴 (migration 098 / formaloo-auto-pull / R5)。自動反映/通知/競合/bootstrap を記録。
CREATE TABLE IF NOT EXISTS formaloo_drift_events (
  id             TEXT PRIMARY KEY,                 -- de_...
  form_id        TEXT NOT NULL,                    -- formaloo_forms.id (FK はアプリ層 / D1 FK off)
  detected_at    TEXT NOT NULL,                    -- 検知時刻 (JST ISO)
  action         TEXT NOT NULL,                    -- notified | auto_applied | conflict_held | bootstrapped
  remote_hash    TEXT,                             -- 検知した Formaloo fingerprint
  prev_hash      TEXT,                             -- 直前 baseline (差分の起点)
  has_warnings   INTEGER NOT NULL DEFAULT 0,       -- 弱化 warnings 有無 (1/0)
  warnings_json  TEXT,                             -- warnings 文言 (任意)
  sync_status_at TEXT,                             -- 検知時の sync_status (競合判定の証跡)
  detail         TEXT,                             -- 補足 (任意)
  created_at     TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);
CREATE INDEX IF NOT EXISTS idx_formaloo_drift_events_form ON formaloo_drift_events (form_id, detected_at);

-- 保存フィルタ (migration 082 / F-4 / T-D1)。データコックピットの絞り込み条件を form 単位で名前付き保存。
CREATE TABLE IF NOT EXISTS formaloo_saved_filters (
  id          TEXT PRIMARY KEY,
  form_id     TEXT NOT NULL,
  name        TEXT NOT NULL,
  filter_json TEXT NOT NULL DEFAULT '{}',
  created_at  TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at  TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);
CREATE INDEX IF NOT EXISTS idx_formaloo_saved_filters_form ON formaloo_saved_filters (form_id);

-- Formaloo workspace registry (migration 094 / F6-1 / envelope 暗号化キー管理)。複数 workspace の
-- API キーを平文で置かず AES-256-GCM 暗号文で保管する台帳。KEK=worker secret FORMALOO_KEK (D-2 / S-1)。
CREATE TABLE IF NOT EXISTS formaloo_workspaces (
  id                 TEXT PRIMARY KEY,
  label              TEXT NOT NULL DEFAULT '',
  business_slug      TEXT,
  key_ciphertext     TEXT NOT NULL,                 -- AES-GCM(base64) 暗号文: API KEY (平文非保持)
  key_iv             TEXT NOT NULL,                 -- KEY 用 12-byte IV (base64)
  secret_ciphertext  TEXT NOT NULL,                 -- AES-GCM(base64) 暗号文: API SECRET (平文非保持)
  secret_iv          TEXT NOT NULL,                 -- SECRET 用 12-byte IV (base64)
  kek_version        INTEGER NOT NULL DEFAULT 1,    -- migration 094: KEK ローテーション前方互換 (Codex gap #4)
  is_active          INTEGER NOT NULL DEFAULT 1,    -- 1=有効 / 0=無効 (enable/disable soft-delete)
  created_at         TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at         TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours'))
);
CREATE INDEX IF NOT EXISTS idx_formaloo_workspaces_active ON formaloo_workspaces (is_active);

-- migration 109: form 単位の Formaloo 定期自動回答ミラー。remote の read-back 完了後だけ synced にする。
CREATE TABLE IF NOT EXISTS formaloo_recurring_submissions (
  id                   TEXT PRIMARY KEY,
  form_id              TEXT NOT NULL REFERENCES formaloo_forms (id) ON DELETE CASCADE,
  idempotency_key      TEXT NOT NULL,
  request_fingerprint  TEXT NOT NULL,
  remote_slug          TEXT,
  schedule_json        TEXT NOT NULL,
  submission_data_json TEXT NOT NULL DEFAULT '{}',
  status               TEXT NOT NULL DEFAULT 'resumed' CHECK (status IN ('resumed', 'paused', 'cancelled')),
  sync_state           TEXT NOT NULL DEFAULT 'pending' CHECK (sync_state IN ('pending', 'synced', 'failed')),
  last_error           TEXT,
  operation_token      TEXT,
  operation_lock_until INTEGER,
  created_at           TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  updated_at           TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%f', 'now', '+9 hours')),
  UNIQUE (form_id, idempotency_key)
);
CREATE UNIQUE INDEX IF NOT EXISTS idx_formaloo_recurring_remote_slug
  ON formaloo_recurring_submissions (form_id, remote_slug)
  WHERE remote_slug IS NOT NULL;
CREATE UNIQUE INDEX IF NOT EXISTS idx_formaloo_recurring_active_fingerprint
  ON formaloo_recurring_submissions (form_id, request_fingerprint)
  WHERE status != 'cancelled';
CREATE INDEX IF NOT EXISTS idx_formaloo_recurring_form
  ON formaloo_recurring_submissions (form_id, created_at DESC);

-- migration 111: owner-gated Formaloo AI analysis history + atomic per-tenant daily reservation.
CREATE TABLE IF NOT EXISTS formaloo_ai_chat_history (
  id                  TEXT PRIMARY KEY,
  tenant_scope        TEXT NOT NULL,
  line_account_id     TEXT NOT NULL,
  form_id             TEXT NOT NULL REFERENCES formaloo_forms (id) ON DELETE CASCADE,
  question            TEXT NOT NULL,
  answer_json         TEXT,
  answer_text         TEXT,
  analysis_slug       TEXT,
  status              TEXT NOT NULL DEFAULT 'pending' CHECK (status IN ('pending', 'completed', 'failed')),
  provider_status     TEXT,
  error_code          TEXT,
  error_message       TEXT,
  credits_consumed    INTEGER NOT NULL DEFAULT 0 CHECK (credits_consumed IN (0, 1)),
  credit_reserved     INTEGER NOT NULL DEFAULT 1 CHECK (credit_reserved IN (0, 1)),
  created_at          TEXT NOT NULL,
  updated_at          TEXT NOT NULL
);
CREATE INDEX IF NOT EXISTS idx_formaloo_ai_chat_history_scope
  ON formaloo_ai_chat_history (tenant_scope, line_account_id, form_id, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_formaloo_ai_chat_daily_guard
  ON formaloo_ai_chat_history (tenant_scope, credit_reserved, created_at);
CREATE UNIQUE INDEX IF NOT EXISTS idx_formaloo_ai_chat_one_pending
  ON formaloo_ai_chat_history (tenant_scope, line_account_id, form_id)
  WHERE status = 'pending';
